import { S3Client, PutObjectCommand, GetObjectCommand, ListObjectsV2Command } from "@aws-sdk/client-s3";
import { Asset, AssetStatus } from '../types';

// Use import.meta.env with VITE_ prefix (standard for Vite applications)
const REGION = (import.meta as any).env.VITE_ASSET_S3_REGION || 'us-east-1';
const BUCKET = (import.meta as any).env.VITE_ASSET_S3_BUCKET;
const ACCESS_KEY = (import.meta as any).env.VITE_ASSET_S3_ACCESS_KEY;
const SECRET_KEY = (import.meta as any).env.VITE_ASSET_S3_SECRET_KEY;

const ASSET_PREFIX = 'assets/';

let client: S3Client | null = null;

const getClient = () => {
  if (!client) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      console.error("Missing S3 Credentials. Expected VITE_ASSET_S3_ACCESS_KEY and VITE_ASSET_S3_SECRET_KEY");
      throw new Error("S3 Credentials are not configured in environment variables.");
    }
    client = new S3Client({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
  }
  return client;
};

const getSiteFileKey = (siteId: string) => {
  const sanitized = siteId.trim().replace(/[^a-zA-Z0-9-_]/g, '_');
  return `${ASSET_PREFIX}site_${sanitized}.json`;
};

const fetchAssetsByKey = async (key: string): Promise<Asset[]> => {
  try {
    const s3 = getClient();
    const command = new GetObjectCommand({
      Bucket: BUCKET,
      Key: key,
    });

    const response = await s3.send(command);
    if (response.Body) {
      const str = await response.Body.transformToString();
      const rawData = JSON.parse(str);
      return rawData.map((item: any) => ({
        ...item,
        status: item.status || item.rmaStatus || AssetStatus.Normal,
      }));
    }
    return [];
  } catch (e: any) {
    if (e.name === 'NoSuchKey' || e.name === 'NotFound' || e.$metadata?.httpStatusCode === 404) {
      return [];
    }
    console.error(`Failed to load assets from ${key}:`, e);
    return [];
  }
};

export const fetchAssets = async (): Promise<Asset[]> => {
  if (!BUCKET || !ACCESS_KEY || !SECRET_KEY) {
    console.warn("VITE_ASSET_S3 variables not found. S3 storage is disabled.");
    return [];
  }

  try {
    const s3 = getClient();
    const listCommand = new ListObjectsV2Command({
      Bucket: BUCKET,
      Prefix: ASSET_PREFIX,
    });

    const listResponse = await s3.send(listCommand);
    const contents = listResponse.Contents || [];

    if (contents.length === 0) {
      return [];
    }

    const filePromises = contents
      .map(file => file.Key)
      .filter((key): key is string => !!key)
      .map(key => fetchAssetsByKey(key));

    const results = await Promise.all(filePromises);
    return results.flat();

  } catch (e: any) {
    console.error('Failed to load asset library from S3:', e);
    throw new Error('Could not connect to S3 Bucket.');
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();

  const assetsBySite = newAssets.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push(asset);
    return acc;
  }, {} as Record<string, Asset[]>);

  const updates = Object.entries(assetsBySite).map(async ([siteId, assetsToAdd]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = [...existingAssets, ...assetsToAdd];

    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });

    return s3.send(putCommand);
  });

  await Promise.all(updates);
};

export const updateAssetStatus = async (assetId: string, siteId: string, newStatus: AssetStatus): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();
  const fileKey = getSiteFileKey(siteId);
  const existingAssets = await fetchAssetsByKey(fileKey);

  const updatedAssets = existingAssets.map(asset => 
    asset.id === assetId ? { ...asset, status: newStatus } : asset
  );

  const putCommand = new PutObjectCommand({
    Bucket: BUCKET,
    Key: fileKey,
    Body: JSON.stringify(updatedAssets),
    ContentType: "application/json",
  });

  await s3.send(putCommand);
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();

  const assetsBySite = assetsToDelete.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push(asset.id);
    return acc;
  }, {} as Record<string, string[]>);

  const updates = Object.entries(assetsBySite).map(async ([siteId, idsToDelete]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = existingAssets.filter(a => !idsToDelete.includes(a.id));

    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });

    return s3.send(putCommand);
  });

  await Promise.all(updates);
};

import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AssetList } from './components/AssetList';
import { AssetForm } from './components/AssetForm';
import { Asset, AssetStatus } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAssetStatus } from './services/storageService';
import { Loader2, Cloud, CloudOff, ShieldCheck } from 'lucide-react';

function App() {
  const [view, setView] = useState<'list' | 'add'>('list');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
    } catch (error) {
      console.error(error);
      setIsConnected(false);
      showNotification('S3 Connection failed. Verify VITE_ASSET_S3 variables.', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to S3`, 'success');
    } catch (error) {
      console.error(error);
      showNotification('Save failed. Check S3 CORS/Permissions.', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdateAssetStatus = async (assetId: string, siteId: string, newStatus: AssetStatus) => {
    try {
      await updateAssetStatus(assetId, siteId, newStatus);
      setAssets(prev => prev.map(a => a.id === assetId ? { ...a, status: newStatus } : a));
      showNotification('Status updated in S3', 'success');
    } catch (error) {
      console.error(error);
      showNotification('Update failed.', 'error');
      throw error; // Let the component handle local UI rollback if needed
    }
  };

  const handleDeleteAssets = async (ids: string[]) => {
    const count = ids.length;
    if (window.confirm(count === 1 ? 'Delete this asset?' : `Delete ${count} assets?`)) {
      setIsSaving(true);
      try {
        const assetsToDelete = assets.filter(a => ids.includes(a.id));
        await deleteAssets(assetsToDelete);
        setAssets(prev => prev.filter(a => !ids.includes(a.id)));
        showNotification('Assets removed from S3', 'success');
      } catch (error) {
        console.error(error);
        showNotification('Delete failed.', 'error');
      } finally {
        setIsSaving(false);
      }
    }
  };

  if (isLoading && assets.length === 0 && isConnected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <div className="loader ease-linear rounded-full border-4 border-t-4 border-slate-200 h-12 w-12 mb-4"></div>
        <p className="text-slate-500 font-medium">Initializing Cloud Environment...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header currentView={view} onNavigate={setView} />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8 relative">

        <div className="mb-4 flex justify-end">
          <div className={`flex items-center gap-2 px-3 py-1 rounded-full text-xs font-semibold border ${
            isConnected 
              ? 'bg-emerald-50 text-emerald-700 border-emerald-200' 
              : isConnected === false 
                ? 'bg-red-50 text-red-700 border-red-200'
                : 'bg-slate-50 text-slate-500 border-slate-200'
          }`}>
            {isConnected ? <Cloud className="h-3 w-3" /> : <CloudOff className="h-3 w-3" />}
            {isConnected ? 'S3 Active' : 'S3 Offline'}
            {isConnected && <ShieldCheck className="h-3 w-3 ml-1" />}
          </div>
        </div>

        {isSaving && (
          <div className="fixed inset-0 bg-white/50 backdrop-blur-sm z-40 flex items-center justify-center">
             <div className="bg-white px-6 py-4 rounded-lg shadow-xl flex items-center gap-3 border border-slate-200">
                <Loader2 className="h-5 w-5 animate-spin text-blue-600" />
                <span className="font-medium text-slate-700">Syncing with AWS S3...</span>
             </div>
          </div>
        )}

        {notification && (
          <div className={`fixed top-20 right-4 px-6 py-4 rounded-lg shadow-lg z-50 animate-fade-in text-white font-medium ${
            notification.type === 'success' ? 'bg-emerald-600' : 'bg-red-600'
          }`}>
            {notification.message}
          </div>
        )}

        {view === 'list' ? (
          <div>
            <div className="mb-6 flex justify-between items-end">
              <div>
                <h2 className="text-2xl font-bold text-slate-900">Live Asset Inventory</h2>
                <p className="text-slate-500 mt-1">
                  Connected to: <strong>{(import.meta as any).env.VITE_ASSET_S3_BUCKET || 'Not Found'}</strong>
