import { S3Client, PutObjectCommand, GetObjectCommand, ListObjectsV2Command } from "@aws-sdk/client-s3";
import { Asset, AssetStatus } from '../types';

const REGION = (import.meta as any).env.VITE_ASSET_S3_REGION || 'us-east-1';
const BUCKET = (import.meta as any).env.VITE_ASSET_S3_BUCKET;
const ACCESS_KEY = (import.meta as any).env.VITE_ASSET_S3_ACCESS_KEY;
const SECRET_KEY = (import.meta as any).env.VITE_ASSET_S3_SECRET_KEY;

const ASSET_PREFIX = 'assets/';

let client: S3Client | null = null;

const getClient = () => {
  if (!client) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      console.error("Missing S3 Credentials. Expected VITE_ASSET_S3_ACCESS_KEY and VITE_ASSET_S3_SECRET_KEY");
      throw new Error("S3 Credentials are not configured in environment variables.");
    }
    client = new S3Client({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
  }
  return client;
};

const getSiteFileKey = (siteId: string) => {
  const sanitized = siteId.trim().replace(/[^a-zA-Z0-9-_]/g, '_');
  return `${ASSET_PREFIX}site_${sanitized}.json`;
};

const fetchAssetsByKey = async (key: string): Promise<Asset[]> => {
  try {
    const s3 = getClient();
    const command = new GetObjectCommand({
      Bucket: BUCKET,
      Key: key,
    });

    const response = await s3.send(command);
    if (response.Body) {
      const str = await response.Body.transformToString();
      const rawData = JSON.parse(str);
      return rawData.map((item: any) => ({
        ...item,
        country: item.country || item.nation || '',
        status: item.status || item.rmaStatus || AssetStatus.Normal,
      }));
    }
    return [];
  } catch (e: any) {
    if (e.name === 'NoSuchKey' || e.name === 'NotFound' || e.$metadata?.httpStatusCode === 404) {
      return [];
    }
    console.error(`Failed to load assets from ${key}:`, e);
    return [];
  }
};

export const fetchAssets = async (): Promise<Asset[]> => {
  if (!BUCKET || !ACCESS_KEY || !SECRET_KEY) {
    console.warn("VITE_ASSET_S3 variables not found. S3 storage is disabled.");
    return [];
  }

  try {
    const s3 = getClient();
    const listCommand = new ListObjectsV2Command({
      Bucket: BUCKET,
      Prefix: ASSET_PREFIX,
    });

    const listResponse = await s3.send(listCommand);
    const contents = listResponse.Contents || [];

    if (contents.length === 0) {
      return [];
    }

    const filePromises = contents
      .map(file => file.Key)
      .filter((key): key is string => !!key)
      .map(key => fetchAssetsByKey(key));

    const results = await Promise.all(filePromises);
    return results.flat();

  } catch (e: any) {
    console.error('Failed to load asset library from S3:', e);
    throw new Error('Could not connect to S3 Bucket.');
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();

  const assetsBySite = newAssets.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push(asset);
    return acc;
  }, {} as Record<string, Asset[]>);

  const updates = Object.entries(assetsBySite).map(async ([siteId, assetsToAdd]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = [...existingAssets, ...assetsToAdd];

    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });

    return s3.send(putCommand);
  });

  await Promise.all(updates);
};

export const updateAssetStatus = async (assetId: string, siteId: string, newStatus: AssetStatus): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();
  const fileKey = getSiteFileKey(siteId);
  const existingAssets = await fetchAssetsByKey(fileKey);

  const updatedAssets = existingAssets.map(asset => 
    asset.id === assetId ? { ...asset, status: newStatus } : asset
  );

  const putCommand = new PutObjectCommand({
    Bucket: BUCKET,
    Key: fileKey,
    Body: JSON.stringify(updatedAssets),
    ContentType: "application/json",
  });

  await s3.send(putCommand);
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket name is missing.");
  const s3 = getClient();

  const assetsBySite = assetsToDelete.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push(asset.id);
    return acc;
  }, {} as Record<string, string[]>);

  const updates = Object.entries(assetsBySite).map(async ([siteId, idsToDelete]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = existingAssets.filter(a => !idsToDelete.includes(a.id));

    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });

    return s3.send(putCommand);
  });

  await Promise.all(updates);
};

import { GoogleGenAI, Type } from "@google/genai";
import { Asset, AssetStatus } from "../types";

// Parse unstructured text into structured asset data
export const parseAssetsFromText = async (text: string): Promise<Partial<Asset>[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Extract asset information from the following text. 
      The text may contain multiple assets. 
      Extract or infer the Country (e.g., "Germany", "UK", "USA") for each asset.
      Infer the Status from the context if possible.
      Valid statuses are: "Normal", "RMA Requested", "RMA Shipped", "RMA Eligible", "RMA Not Eligible", "Deprecated", "Unknown".
      If no specific status context is found, default to "Normal".

      Text to process:
      "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              model: { type: Type.STRING, description: "The model name or number of the asset" },
              serialNumber: { type: Type.STRING, description: "The serial number" },
              siteId: { type: Type.STRING, description: "The location or Site ID" },
              country: { type: Type.STRING, description: "The country where the asset is located" },
              status: { 
                type: Type.STRING, 
                enum: Object.values(AssetStatus),
                description: "The status of the asset" 
              }
            },
            required: ["model", "serialNumber", "siteId", "country", "status"]
          }
        }
      }
    });

    if (response.text) {
      return JSON.parse(response.text) as Partial<Asset>[];
    }
    return [];
  } catch (error) {
    console.error("Gemini parse error:", error);
    throw new Error("Failed to parse asset data using AI.");
  }
};

// Generate a summary report of the assets
export const generateAssetReport = async (assets: Asset[]): Promise<string> => {
  if (assets.length === 0) return "No assets to analyze.";

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const dataStr = JSON.stringify(assets.map(a => ({
      model: a.model,
      site: a.siteId,
      country: a.country,
      status: a.status
    })));

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analyze this asset dataset and provide a brief executive summary suitable for a dashboard.
      Focus on:
      1. Total count and breakdown by Country and Site ID.
      2. Identify any patterns in Status/RMA geographically or by model.
      3. Actionable recommendations.

      Keep it concise (max 200 words). Use Markdown for formatting.

      Dataset:
      ${dataStr}`
    });

    return response.text || "Analysis failed to generate text.";
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "Could not generate AI report at this time.";
  }
};

import React, { useState, useRef } from 'react';
import { Asset, AssetStatus } from '../types';
