interface AssetFormProps {
  onAddAssets: (assets: Asset[]) => void;
  onCancel: () => void;
}

export const AssetForm: React.FC<AssetFormProps> = ({ onAddAssets, onCancel }) => {
  const [mode, setMode] = useState<'manual' | 'ai' | 'bulk'>('manual');

  // Manual State
  const [manualForm, setManualForm] = useState({
    model: '',
    serialNumber: '',
    siteId: '',
    country: '',
    status: AssetStatus.Normal
  });

  // AI State
  const [aiInput, setAiInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Bulk State
  const [bulkPreview, setBulkPreview] = useState<Asset[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.model || !manualForm.serialNumber || !manualForm.siteId || !manualForm.country) {
      setError("Please fill in all required fields.");
      return;
    }

    const newAsset: Asset = {
      id: uuidv4(),
      ...manualForm,
      createdAt: Date.now()
    };

    onAddAssets([newAsset]);
  };

  const handleAiParse = async () => {
    if (!aiInput.trim()) return;

    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parseAssetsFromText(aiInput);

      if (parsedData.length === 0) {
        setError("AI couldn't find any assets in the text. Try rephrasing or use manual entry.");
      } else {
        const newAssets: Asset[] = parsedData.map(p => ({
          id: uuidv4(),
          model: p.model || 'Unknown',
          serialNumber: p.serialNumber || 'Unknown',
          siteId: p.siteId || 'Unknown',
          country: p.country || '',
          status: (p.status as AssetStatus) || AssetStatus.Normal,
          createdAt: Date.now()
        }));
        onAddAssets(newAssets);
      }
    } catch (err) {
      setError("Failed to process text. Check your API connection.");
    } finally {
      setIsProcessing(false);
    }
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    Papa.parse(file, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        const assets: Asset[] = [];

        results.data.forEach((row: any) => {
          const normalizedRow: Record<string, string> = {};
          Object.keys(row).forEach(key => {
            normalizedRow[key.toLowerCase().trim()] = row[key];
          });

          const model = normalizedRow['model'] || normalizedRow['asset model'] || normalizedRow['product'];
          const serial = normalizedRow['serial number'] || normalizedRow['serial'] || normalizedRow['sn'] || normalizedRow['serial no'];
          const site = normalizedRow['site id'] || normalizedRow['site'] || normalizedRow['location'];
          const country = normalizedRow['country'] || normalizedRow['nation'] || normalizedRow['origin'];
          const status = normalizedRow['status'] || normalizedRow['rma status'] || normalizedRow['rma'];

          if (model && serial && site) {
            let assetStatus = AssetStatus.Normal;
            if (status) {
              const s = status.trim();
              const foundStatus = Object.values(AssetStatus).find(
                enumVal => enumVal.toLowerCase() === s.toLowerCase()
              );
              if (foundStatus) {
                assetStatus = foundStatus;
              } else if (s.toLowerCase().includes('request')) {
                assetStatus = AssetStatus.RMARequested;
              } else if (s.toLowerCase().includes('ship')) {
                assetStatus = AssetStatus.RMAShipped;
              } else if (s.toLowerCase().includes('not eligible')) {
                assetStatus = AssetStatus.RMANotEligible;
              } else if (s.toLowerCase().includes('eligible')) {
                assetStatus = AssetStatus.RMAEligible;
              } else if (s.toLowerCase().includes('deprecated')) {
                assetStatus = AssetStatus.Deprecated;
              } else {
                assetStatus = AssetStatus.Unknown;
              }
            }

            assets.push({
              id: uuidv4(),
              model: model.trim(),
              serialNumber: serial.trim(),
              siteId: site.trim(),
              country: country ? country.trim() : '',
              status: assetStatus,
              createdAt: Date.now()
            });
          }
        });

        if (assets.length === 0) {
          setError("No valid assets found in CSV. Please check the column headers (Model, Serial Number, Site ID, Country).");
        } else {
          setBulkPreview(assets);
          setError(null);
        }
      },
      error: (err) => {
        setError(`Failed to parse CSV: ${err.message}`);
      }
    });

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const downloadTemplate = () => {
    const csvContent = "Model,Serial Number,Site ID,Country,Status\nCisco Catalyst 9200,FOC12345678,NYC-01,USA,Normal\nLenovo ThinkPad X1,PF123456,LON-HQ,UK,RMA Requested";
    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = "asset_template.csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  const confirmBulkUpload = () => {
    onAddAssets(bulkPreview);
    setBulkPreview([]);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex flex-wrap gap-2 md:gap-4 p-1 bg-slate-100 rounded-lg w-full md:w-fit mx-auto justify-center">
        <button
          onClick={() => setMode('manual')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all ${
            mode === 'manual' 
              ? 'bg-white text-blue-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          Manual Entry
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'bulk' 
              ? 'bg-white text-emerald-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <FileSpreadsheet className="h-4 w-4" />
          Bulk Upload (CSV)
        </button>
        <button
          onClick={() => setMode('ai')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'ai' 
              ? 'bg-white text-purple-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <Bot className="h-4 w-4" />
          AI Import
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2 text-sm border border-red-100">
            <AlertCircle className="h-5 w-5 flex-shrink-0" />
            {error}
          </div>
        )}

        {mode === 'manual' && (
          <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Asset Model *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.model}
                  onChange={e => setManualForm({...manualForm, model: e.target.value})}
                  placeholder="e.g. Zebra MC33K"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Serial Number *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.serialNumber}
                  onChange={e => setManualForm({...manualForm, serialNumber: e.target.value})}
                  placeholder="e.g. S2000003454354"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Site ID *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.siteId}
                  onChange={e => setManualForm({...manualForm, siteId: e.target.value})}
                  placeholder="e.g. XDT3"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Country *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.country}
                  onChange={e => setManualForm({...manualForm, country: e.target.value})}
                  placeholder="e.g. Germany"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Status</label>
                <select
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                  value={manualForm.status}
                  onChange={e => setManualForm({...manualForm, status: e.target.value as AssetStatus})}
                >
                  {Object.values(AssetStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button
                type="submit"
                className="flex-1 bg-blue-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2"
              >
                <Save className="h-5 w-5" />
                Save Asset
              </button>
              <button
                type="button"
                onClick={onCancel}
                className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
              >
                Cancel
              </button>
            </div>
          </form>
        )}

        {mode === 'bulk' && (
           <div className="space-y-6">
             {bulkPreview.length === 0 ? (
               <>
                <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100">
                  <h3 className="text-emerald-900 font-semibold mb-2 flex items-center gap-2">
                    <FileSpreadsheet className="h-5 w-5" />
                    Bulk Upload (CSV)
                  </h3>
                  <p className="text-sm text-emerald-800">
                    Upload a CSV file to import multiple assets at once. 
                    Ensure your CSV has headers like <strong>Model</strong>, <strong>Serial Number</strong>, <strong>Site ID</strong>, and <strong>Country</strong>.
                  </p>
                </div>

                <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center hover:bg-slate-50 transition-colors cursor-pointer"
                     onClick={() => fileInputRef.current?.click()}>
                  <input 
                    type="file" 
                    accept=".csv" 
                    className="hidden" 
                    ref={fileInputRef} 
                    onChange={handleFileUpload}
                  />
                  <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Upload className="h-8 w-8" />
                  </div>
                  <h3 className="text-lg font-medium text-slate-900">Click to upload or drag and drop</h3>
                  <p className="text-slate-500 text-sm mt-1">CSV files only (max 5MB)</p>
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={downloadTemplate}
                    className="text-sm text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1"
                  >
                    <Download className="h-4 w-4" />
                    Download CSV Template
                  </button>
                </div>

                <div className="flex justify-end pt-4">
                  <button
                    type="button"
                    onClick={onCancel}
                    className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
                  >
                    Cancel
                  </button>
                </div>
               </>
             ) : (
               <div className="space-y-4">
                 <div className="flex items-center justify-between">
                   <h3 className="font-semibold text-slate-900 flex items-center gap-2">
                     <CheckCircle className="h-5 w-5 text-emerald-600" />
                     {bulkPreview.length} assets ready to import
                   </h3>
                   <button 
                    onClick={() => setBulkPreview([])}
                    className="text-slate-400 hover:text-red-500"
                   >
                     <X className="h-5 w-5" />
                   </button>
                 </div>

                 <div className="border border-slate-200 rounded-lg overflow-hidden max-h-80 overflow-y-auto">
                   <table className="w-full text-sm text-left">
                     <thead className="bg-slate-50 text-slate-600 font-medium sticky top-0">
                       <tr>
                         <th className="px-4 py-2">Model</th>
                         <th className="px-4 py-2">Serial</th>
                         <th className="px-4 py-2">Site</th>
                         <th className="px-4 py-2">Country</th>
                         <th className="px-4 py-2">Status</th>
                       </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                       {bulkPreview.map((asset, i) => (
                         <tr key={i}>
                           <td className="px-4 py-2">{asset.model}</td>
                           <td className="px-4 py-2 font-mono text-xs">{asset.serialNumber}</td>
                           <td className="px-4 py-2">{asset.siteId}</td>
                           <td className="px-4 py-2">{asset.country}</td>
                           <td className="px-4 py-2">{asset.status}</td>
                         </tr>
                       ))}
                     </tbody>
                   </table>
                 </div>

                 <div className="flex gap-4 pt-2">
                   <button
                     onClick={confirmBulkUpload}
                     className="flex-1 bg-emerald-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2"
                   >
                     <Save className="h-5 w-5" />
                     Import {bulkPreview.length} Assets
                   </button>
                   <button
                     type="button"
                     onClick={() => setBulkPreview([])}
                     className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
                   >
                     Cancel
                   </button>
                 </div>
               </div>
             )}
           </div>
        )}

        {mode === 'ai' && (
          <div className="space-y-6">
            <div className="bg-purple-50 p-4 rounded-lg border border-purple-100">
              <h3 className="text-purple-900 font-semibold mb-2 flex items-center gap-2">
                <Bot className="h-5 w-5" />
                AI Smart Import
              </h3>
              <p className="text-sm text-purple-800">
                Paste any unstructured text below (e.g., email threads, chat logs, or messy Excel copy-pastes). 
                Gemini will automatically extract models, serial numbers, sites, countries, and infer the status.
              </p>
            </div>

            <div>
              <textarea
                className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none h-48 resize-none font-mono text-sm"
                value={aiInput}
                onChange={e => setAiInput(e.target.value)}
                placeholder={`Example:\nHi team, the switch at Site LA-05 (Model: C9300-24T, SN: FCW2345L0) in Germany is eligible for RMA. \nAlso, received a new Router ISR4331 at NY-02, USA, SN: FDO2451X, working normally.`}
              />
            </div>

            <div className="flex gap-4">
              <button
                onClick={handleAiParse}
                disabled={isProcessing || !aiInput.trim()}
                className="flex-1 bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-3 rounded-lg font-medium hover:from-purple-700 hover:to-indigo-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-md"
              >
                {isProcessing ? (
                  <>Processing...</>
                ) : (
                  <>
                    <SparklesIcon className="h-5 w-5" />
                    Extract & Save
                  </>
                )}
              </button>
               <button
                type="button"
                onClick={onCancel}
                className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
              >
                Cancel
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const SparklesIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z" />
  </svg>
);

import React, { useState, useMemo } from 'react';
import { Asset, AssetStatus } from '../types';
import { Search, Filter, Sparkles, Trash2, Download, Loader2, Globe } from 'lucide-react';
import { generateAssetReport } from '../services/geminiService';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateStatus: (assetId: string, siteId: string, newStatus: AssetStatus) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateStatus }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [updatingAssetId, setUpdatingAssetId] = useState<string | null>(null);

  const filteredAssets = useMemo(() => {
    return assets.filter(asset => {
      const matchesSearch = 
        asset.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.serialNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.siteId.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.country.toLowerCase().includes(searchTerm.toLowerCase());

      const matchesStatus = statusFilter === 'All' || asset.status === statusFilter;

      return matchesSearch && matchesStatus;
    });
  }, [assets, searchTerm, statusFilter]);

  const allSelected = filteredAssets.length > 0 && filteredAssets.every(a => selectedIds.has(a.id));
  const isIndeterminate = filteredAssets.some(a => selectedIds.has(a.id)) && !allSelected;

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.checked) {
      const newSelected = new Set(selectedIds);
      filteredAssets.forEach(a => newSelected.add(a.id));
      setSelectedIds(newSelected);
    } else {
      const newSelected = new Set(selectedIds);
      filteredAssets.forEach(a => newSelected.delete(a.id));
      setSelectedIds(newSelected);
    }
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) {
      newSelected.delete(id);
    } else {
      newSelected.add(id);
    }
    setSelectedIds(newSelected);
  };

  const handleStatusChange = async (asset: Asset, newStatus: AssetStatus) => {
    if (asset.status === newStatus) return;

    setUpdatingAssetId(asset.id);
    try {
      await onUpdateStatus(asset.id, asset.siteId, newStatus);
    } catch (e) {
      // Handled in App
    } finally {
      setUpdatingAssetId(null);
    }
  };

  const handleBulkDelete = () => {
    onDelete(Array.from(selectedIds));
    setSelectedIds(new Set()); 
  };

  const handleAnalyze = async () => {
    setIsAnalyzing(true);
    setAnalysis(null);
    try {
      const report = await generateAssetReport(filteredAssets);
      setAnalysis(report);
    } catch (error) {
      console.error(error);
    } finally {
      setIsAnalyzing(false);
    }
  };

  const exportToCSV = () => {
    const headers = ["Model", "Serial Number", "Site ID", "Country", "Status", "Date"];
    const rows = filteredAssets.map(a => [
      a.model,
      a.serialNumber,
      a.siteId,
      a.country,
      a.status,
      new Date(a.createdAt).toLocaleDateString()
    ]);

    const csvContent = "data:text/csv;charset=utf-8," + 
      [headers.join(","), ...rows.map(r => r.join(","))].join("\n");

    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "assets_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const getStatusColorClass = (status: AssetStatus) => {
    switch (status) {
      case AssetStatus.Normal: return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case AssetStatus.RMARequested: return 'bg-yellow-50 text-yellow-700 border-yellow-200';
      case AssetStatus.RMAShipped: return 'bg-purple-50 text-purple-700 border-purple-200';
      case AssetStatus.RMAEligible: return 'bg-blue-50 text-blue-700 border-blue-200';
      case AssetStatus.RMANotEligible: return 'bg-orange-50 text-orange-700 border-orange-200';
      case AssetStatus.Deprecated: return 'bg-red-50 text-red-700 border-red-200';
      default: return 'bg-gray-50 text-gray-700 border-gray-200';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Controls */}
      <div className="bg-white p-4 rounded-xl shadow-sm border border-slate-200 flex flex-col xl:flex-row gap-4 justify-between items-center">
        <div className="flex flex-col md:flex-row items-center gap-4 w-full xl:w-auto">
          <div className="relative w-full md:w-80">
            <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400" />
            <input
              type="text"
              placeholder="Search Model, Serial, Site, Country..."
              className="w-full pl-10 pr-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 focus:border-blue-500 outline-none text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex flex-col sm:flex-row gap-4 w-full md:w-auto">
            <div className="relative w-full sm:w-auto">
              <Filter className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-slate-400" />
              <select
                className="w-full sm:w-auto pl-10 pr-8 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none text-sm appearance-none bg-white"
                value={statusFilter}
                onChange={(e) => setStatusFilter(e.target.value)}
              >
                <option value="All">All Statuses</option>
                {Object.values(AssetStatus).map(s => (
                  <option key={s} value={s}>{s}</option>
                ))}
              </select>
            </div>
          </div>
        </div>

        <div className="flex gap-2 w-full xl:w-auto flex-wrap md:flex-nowrap">
          {selectedIds.size > 0 && (
            <button
              onClick={handleBulkDelete}
              className="flex items-center justify-center gap-2 px-4 py-2 bg-red-50 border border-red-200 text-red-700 rounded-lg text-sm font-medium hover:bg-red-100 transition-colors w-full md:w-auto animate-fade-in"
            >
              <Trash2 className="h-4 w-4" />
              Delete Selected ({selectedIds.size})
            </button>
          )}

          <button
            onClick={exportToCSV}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-white border border-slate-300 text-slate-700 rounded-lg text-sm font-medium hover:bg-slate-50 transition-colors w-full md:w-auto"
          >
            <Download className="h-4 w-4" />
            Export CSV
          </button>
          <button
            onClick={handleAnalyze}
            disabled={isAnalyzing || filteredAssets.length === 0}
            className="flex items-center justify-center gap-2 px-4 py-2 bg-gradient-to-r from-indigo-500 to-purple-600 text-white rounded-lg text-sm font-medium hover:from-indigo-600 hover:to-purple-700 transition-all shadow-md w-full md:w-auto disabled:opacity-50"
          >
            <Sparkles className={`h-4 w-4 ${isAnalyzing ? 'animate-spin' : ''}`} />
            {isAnalyzing ? 'Analyzing...' : 'AI Insights'}
          </button>
        </div>
      </div>

      {analysis && (
        <div className="bg-gradient-to-br from-indigo-50 to-purple-50 p-6 rounded-xl border border-indigo-100 shadow-sm animate-fade-in">
          <h3 className="flex items-center gap-2 text-indigo-900 font-semibold mb-3">
            <Sparkles className="h-5 w-5 text-indigo-600" />
            AI Executive Summary
          </h3>
          <div className="prose prose-sm prose-indigo max-w-none text-slate-700">
            {analysis.split('\n').map((line, i) => (
              <p key={i} className="mb-1">{line}</p>
            ))}
          </div>
        </div>
      )}

      {/* Table */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-slate-50 text-slate-600 font-medium border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 w-12 text-center">
                   <input 
                    type="checkbox" 
                    className="w-4 h-4 text-blue-600 bg-white border-slate-300 rounded focus:ring-blue-500 focus:ring-2 cursor-pointer"
                    checked={allSelected}
                    ref={input => {
                      if (input) input.indeterminate = isIndeterminate;
                    }}
                    onChange={handleSelectAll}
                   />
                </th>
                <th className="px-6 py-4">Model</th>
                <th className="px-6 py-4">Serial Number</th>
                <th className="px-6 py-4 text-center">Site ID</th>
                <th className="px-6 py-4 text-center">Country</th>
                <th className="px-6 py-4">Status (Live Edit)</th>
                <th className="px-6 py-4 text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-100">
              {filteredAssets.length > 0 ? (
                filteredAssets.map((asset) => (
                  <tr key={asset.id} className={`hover:bg-slate-50 transition-colors group ${selectedIds.has(asset.id) ? 'bg-blue-50/50' : ''}`}>
                    <td className="px-6 py-4 text-center">
                      <input 
                        type="checkbox" 
                        className="w-4 h-4 text-blue-600 bg-white border-slate-300 rounded focus:ring-blue-500 focus:ring-2 cursor-pointer"
                        checked={selectedIds.has(asset.id)}
                        onChange={() => toggleSelect(asset.id)}
                      />
                    </td>
                    <td className="px-6 py-4 font-medium text-slate-900">{asset.model}</td>
                    <td className="px-6 py-4 text-slate-600 font-mono text-xs">{asset.serialNumber}</td>
                    <td className="px-6 py-4 text-center">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-semibold bg-slate-100 text-slate-600 border border-slate-200">
                        {asset.siteId}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex items-center justify-center gap-1.5 text-slate-600">
                        <Globe className="h-3.5 w-3.5 text-slate-400" />
                        <span className="font-medium">{asset.country || 'N/A'}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      {updatingAssetId === asset.id ? (
                        <div className="flex items-center gap-2 px-2 py-1 text-xs text-blue-600 font-medium italic">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          Saving...
                        </div>
                      ) : (
                        <div className="relative group/status w-fit">
                          <select
                            value={asset.status}
                            onChange={(e) => handleStatusChange(asset, e.target.value as AssetStatus)}
                            className={`
                              appearance-none cursor-pointer px-3 py-1 pr-8 rounded-full text-xs font-bold border outline-none focus:ring-2 focus:ring-blue-500/20 transition-all
                              ${getStatusColorClass(asset.status)}
                            `}
                          >
                            {Object.values(AssetStatus).map(s => (
                              <option key={s} value={s} className="bg-white text-slate-900">{s}</option>
                            ))}
                          </select>
                          <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none opacity-50 group-hover/status:opacity-100 transition-opacity">
                            <svg className="h-3 w-3 fill-current" viewBox="0 0 20 20">
                              <path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" />
                            </svg>
                          </div>
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <button
                        onClick={() => onDelete([asset.id])}
                        className="text-slate-300 hover:text-red-500 transition-colors p-2 rounded-md hover:bg-red-50"
                        title="Delete Asset"
                      >
                        <Trash2 className="h-4 w-4" />
                      </button>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                    <p className="mb-2 text-lg font-medium">No assets matched your search</p>
                    <p className="text-sm">Try adjusting filters or adding new assets.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
      <div className="flex justify-between items-center text-[10px] uppercase tracking-wider font-bold text-slate-400 px-2">
         <div>
          {selectedIds.size > 0 ? `${selectedIds.size} Assets Selected` : ''}
         </div>
         <div>
           Inventory Count: {filteredAssets.length} / {assets.length}
         </div>
      </div>
    </div>
  );
};

import React, { useState, useRef } from 'react';
import { Asset, AssetStatus } from '../types';
import { parseAssetsFromText } from '../services/geminiService';
import { Bot, Save, AlertCircle, CheckCircle, Upload, FileSpreadsheet, Download, X } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetFormProps {
  onAddAssets: (assets: Asset[]) => void;
  onCancel: () => void;
}

export const AssetForm: React.FC<AssetFormProps> = ({ onAddAssets, onCancel }) => {
  const [mode, setMode] = useState<'manual' | 'ai' | 'bulk'>('manual');

  // Manual State
  const [manualForm, setManualForm] = useState({
    model: '',
    serialNumber: '',
    siteId: '',
    country: '',
    status: AssetStatus.Normal
  });

  // AI State
  const [aiInput, setAiInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Bulk State
  const [bulkPreview, setBulkPreview] = useState<Asset[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.model || !manualForm.serialNumber || !manualForm.siteId || !manualForm.country) {
      setError("Please fill in all required fields.");
      return;
    }

    const newAsset: Asset = {
      id: uuidv4(),
      ...manualForm,
      createdAt: Date.now()
    };

    onAddAssets([newAsset]);
  };

  const handleAiParse = async () => {
    if (!aiInput.trim()) return;

    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parseAssetsFromText(aiInput);

      if (parsedData.length === 0) {
        setError("AI couldn't find any assets in the text. Try rephrasing or use manual entry.");
      } else {
        const newAssets: Asset[] = parsedData.map(p => ({
          id: uuidv4(),
          model: p.model || 'Unknown',
          serialNumber: p.serialNumber || 'Unknown',
          siteId: p.siteId || 'Unknown',
          country: p.country || '',
          status: (p.status as AssetStatus) || AssetStatus.Normal,
          createdAt: Date.now()
        }));
        onAddAssets(newAssets);
      }
    } catch (err) {
      setError("Failed to process text. Check your API connection.");
    } finally {
      setIsProcessing(false);
    }
  };

  const processRowToAsset = (row: any): Asset | null => {
    const normalizedRow: Record<string, any> = {};
    Object.keys(row).forEach(key => {
      normalizedRow[key.toLowerCase().trim()] = row[key];
    });

    // Flexible mapping for headers
    const model = normalizedRow['model'] || normalizedRow['asset model'] || normalizedRow['product'] || normalizedRow['device'] || normalizedRow['item'];
    const serial = normalizedRow['serial number'] || normalizedRow['serial'] || normalizedRow['sn'] || normalizedRow['serial no'] || normalizedRow['s/n'];
    const site = normalizedRow['site id'] || normalizedRow['site'] || normalizedRow['location'] || normalizedRow['siteid'];
    const country = normalizedRow['country'] || normalizedRow['nation'] || normalizedRow['origin'] || normalizedRow['region'];
    const status = normalizedRow['status'] || normalizedRow['rma status'] || normalizedRow['rma'] || normalizedRow['condition'];

    if (model && serial && site) {
      let assetStatus = AssetStatus.Normal;
      if (status) {
        const s = String(status).trim();
        const foundStatus = Object.values(AssetStatus).find(
          enumVal => enumVal.toLowerCase() === s.toLowerCase()
        );
        if (foundStatus) {
          assetStatus = foundStatus;
        } else if (s.toLowerCase().includes('request')) {
          assetStatus = AssetStatus.RMARequested;
        } else if (s.toLowerCase().includes('ship')) {
          assetStatus = AssetStatus.RMAShipped;
        } else if (s.toLowerCase().includes('not eligible')) {
          assetStatus = AssetStatus.RMANotEligible;
        } else if (s.toLowerCase().includes('eligible')) {
          assetStatus = AssetStatus.RMAEligible;
        } else if (s.toLowerCase().includes('deprecated')) {
          assetStatus = AssetStatus.Deprecated;
        } else {
          assetStatus = AssetStatus.Unknown;
        }
      }

      return {
        id: uuidv4(),
        model: String(model).trim(),
        serialNumber: String(serial).trim(),
        siteId: String(site).trim(),
        country: country ? String(country).trim() : '',
        status: assetStatus,
        createdAt: Date.now()
      };
    }
    return null;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const fileExt = file.name.split('.').pop()?.toLowerCase();

    if (fileExt === 'csv') {
      Papa.parse(file, {
        header: true,
        skipEmptyLines: true,
        complete: (results) => {
          const assets: Asset[] = results.data
            .map(row => processRowToAsset(row))
            .filter((a): a is Asset => a !== null);

          if (assets.length === 0) {
            setError("No valid assets found in CSV. Please check the column headers (Model, Serial Number, Site ID, Country).");
          } else {
            setBulkPreview(assets);
            setError(null);
          }
        },
        error: (err) => {
          setError(`Failed to parse CSV: ${err.message}`);
        }
      });
    } else if (fileExt === 'xlsx' || fileExt === 'xls') {
      const reader = new FileReader();
      reader.onload = (evt) => {
        try {
          const bstr = evt.target?.result;
          const wb = XLSX.read(bstr, { type: 'binary' });
          const wsname = wb.SheetNames[0];
          const ws = wb.Sheets[wsname];
          const data = XLSX.utils.sheet_to_json(ws);

          const assets: Asset[] = data
            .map(row => processRowToAsset(row))
            .filter((a): a is Asset => a !== null);

          if (assets.length === 0) {
            setError("No valid assets found in Excel file. Ensure it has headers like Model, Serial, Site, Country.");
          } else {
            setBulkPreview(assets);
            setError(null);
          }
        } catch (err: any) {
          setError(`Failed to parse Excel file: ${err.message}`);
        }
      };
      reader.readAsBinaryString(file);
    } else {
      setError("Unsupported file format. Please use .csv, .xlsx, or .xls");
    }

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const downloadTemplate = () => {
    const csvContent = "Model,Serial Number,Site ID,Country,Status\nCisco Catalyst 9200,FOC12345678,NYC-01,USA,Normal\nLenovo ThinkPad X1,PF123456,LON-HQ,UK,RMA Requested";
    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = "asset_template.csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  const confirmBulkUpload = () => {
    onAddAssets(bulkPreview);
    setBulkPreview([]);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex flex-wrap gap-2 md:gap-4 p-1 bg-slate-100 rounded-lg w-full md:w-fit mx-auto justify-center">
        <button
          onClick={() => setMode('manual')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all ${
            mode === 'manual' 
              ? 'bg-white text-blue-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          Manual Entry
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'bulk' 
              ? 'bg-white text-emerald-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <FileSpreadsheet className="h-4 w-4" />
          Bulk Upload (Excel/CSV)
        </button>
        <button
          onClick={() => setMode('ai')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'ai' 
              ? 'bg-white text-purple-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <Bot className="h-4 w-4" />
          AI Import
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2 text-sm border border-red-100">
            <AlertCircle className="h-5 w-5 flex-shrink-0" />
            {error}
          </div>
        )}

        {mode === 'manual' && (
          <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Asset Model *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.model}
                  onChange={e => setManualForm({...manualForm, model: e.target.value})}
                  placeholder="e.g. Zebra MC33K"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Serial Number *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.serialNumber}
                  onChange={e => setManualForm({...manualForm, serialNumber: e.target.value})}
                  placeholder="e.g. S2000003454354"
                />
              </div>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Site ID *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.siteId}
                  onChange={e => setManualForm({...manualForm, siteId: e.target.value})}
                  placeholder="e.g. XDT3"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Country *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.country}
                  onChange={e => setManualForm({...manualForm, country: e.target.value})}
                  placeholder="e.g. Germany"
                />
              </div>
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Status</label>
                <select
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                  value={manualForm.status}
                  onChange={e => setManualForm({...manualForm, status: e.target.value as AssetStatus})}
                >
                  {Object.values(AssetStatus).map(s => (
                    <option key={s} value={s}>{s}</option>
                  ))}
                </select>
              </div>
            </div>

            <div className="flex gap-4 pt-4">
              <button
                type="submit"
                className="flex-1 bg-blue-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2"
              >
                <Save className="h-5 w-5" />
                Save Asset
              </button>
              <button
                type="button"
                onClick={onCancel}
                className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
              >
                Cancel
              </button>
            </div>
          </form>
        )}

        {mode === 'bulk' && (
           <div className="space-y-6">
             {bulkPreview.length === 0 ? (
               <>
                <div className="bg-emerald-50 p-4 rounded-lg border border-emerald-100">
                  <h3 className="text-emerald-900 font-semibold mb-2 flex items-center gap-2">
                    <FileSpreadsheet className="h-5 w-5" />
                    Bulk Upload (Excel/CSV)
                  </h3>
                  <p className="text-sm text-emerald-800">
                    Upload an Excel (.xlsx, .xls) or CSV file. 
                    The file should have separate columns for <strong>Model</strong>, <strong>Serial Number</strong>, <strong>Site ID</strong>, and <strong>Country</strong>.
                  </p>
                </div>

                <div className="border-2 border-dashed border-slate-300 rounded-xl p-8 text-center hover:bg-slate-50 transition-colors cursor-pointer"
                     onClick={() => fileInputRef.current?.click()}>
                  <input 
                    type="file" 
                    accept=".csv,.xlsx,.xls" 
                    className="hidden" 
                    ref={fileInputRef} 
                    onChange={handleFileUpload}
                  />
                  <div className="w-16 h-16 bg-blue-50 text-blue-600 rounded-full flex items-center justify-center mx-auto mb-4">
                    <Upload className="h-8 w-8" />
                  </div>
                  <h3 className="text-lg font-medium text-slate-900">Click to upload or drag and drop</h3>
                  <p className="text-slate-500 text-sm mt-1">CSV, XLSX, XLS (max 10MB)</p>
                </div>

                <div className="flex justify-center">
                  <button 
                    onClick={downloadTemplate}
                    className="text-sm text-blue-600 hover:text-blue-800 font-medium flex items-center gap-1"
                  >
                    <Download className="h-4 w-4" />
                    Download CSV Template
                  </button>
                </div>

                <div className="flex justify-end pt-4">
                  <button
                    type="button"
                    onClick={onCancel}
                    className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
                  >
                    Cancel
                  </button>
                </div>
               </>
             ) : (
               <div className="space-y-4">
                 <div className="flex items-center justify-between">
                   <h3 className="font-semibold text-slate-900 flex items-center gap-2">
                     <CheckCircle className="h-5 w-5 text-emerald-600" />
                     {bulkPreview.length} assets ready to import
                   </h3>
                   <button 
                    onClick={() => setBulkPreview([])}
                    className="text-slate-400 hover:text-red-500"
                   >
                     <X className="h-5 w-5" />
                   </button>
                 </div>

                 <div className="border border-slate-200 rounded-lg overflow-hidden max-h-80 overflow-y-auto">
                   <table className="w-full text-sm text-left">
                     <thead className="bg-slate-50 text-slate-600 font-medium sticky top-0">
                       <tr>
                         <th className="px-4 py-2">Model</th>
                         <th className="px-4 py-2">Serial</th>
                         <th className="px-4 py-2">Site</th>
                         <th className="px-4 py-2">Country</th>
                         <th className="px-4 py-2">Status</th>
                       </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                       {bulkPreview.map((asset, i) => (
                         <tr key={i}>
                           <td className="px-4 py-2">{asset.model}</td>
                           <td className="px-4 py-2 font-mono text-xs">{asset.serialNumber}</td>
                           <td className="px-4 py-2">{asset.siteId}</td>
                           <td className="px-4 py-2">{asset.country}</td>
                           <td className="px-4 py-2">{asset.status}</td>
                         </tr>
                       ))}
                     </tbody>
                   </table>
                 </div>

                 <div className="flex gap-4 pt-2">
                   <button
                     onClick={confirmBulkUpload}
                     className="flex-1 bg-emerald-600 text-white px-6 py-3 rounded-lg font-medium hover:bg-emerald-700 transition-colors flex items-center justify-center gap-2"
                   >
                     <Save className="h-5 w-5" />
                     Import {bulkPreview.length} Assets
                   </button>
                   <button
                     type="button"
                     onClick={() => setBulkPreview([])}
                     className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
                   >
                     Cancel
                   </button>
                 </div>
               </div>
             )}
           </div>
        )}

        {mode === 'ai' && (
          <div className="space-y-6">
            <div className="bg-purple-50 p-4 rounded-lg border border-purple-100">
              <h3 className="text-purple-900 font-semibold mb-2 flex items-center gap-2">
                <Bot className="h-5 w-5" />
                AI Smart Import
              </h3>
              <p className="text-sm text-purple-800">
                Paste any unstructured text below (e.g., email threads, chat logs, or messy Excel copy-pastes). 
                Gemini will automatically extract models, serial numbers, sites, countries, and infer the status.
              </p>
            </div>

            <div>
              <textarea
                className="w-full px-4 py-3 border border-slate-300 rounded-lg focus:ring-2 focus:ring-purple-500 outline-none h-48 resize-none font-mono text-sm"
                value={aiInput}
                onChange={e => setAiInput(e.target.value)}
                placeholder={`Example:\nHi team, the switch at Site LA-05 (Model: C9300-24T, SN: FCW2345L0) in Germany is eligible for RMA. \nAlso, received a new Router ISR4331 at NY-02, USA, SN: FDO2451X, working normally.`}
              />
            </div>

            <div className="flex gap-4">
              <button
                onClick={handleAiParse}
                disabled={isProcessing || !aiInput.trim()}
                className="flex-1 bg-gradient-to-r from-purple-600 to-indigo-600 text-white px-6 py-3 rounded-lg font-medium hover:from-purple-700 hover:to-indigo-700 transition-all flex items-center justify-center gap-2 disabled:opacity-50 shadow-md"
              >
                {isProcessing ? (
                  <>Processing...</>
                ) : (
                  <>
                    <SparklesIcon className="h-5 w-5" />
                    Extract & Save
                  </>
                )}
              </button>
               <button
                type="button"
                onClick={onCancel}
                className="px-6 py-3 rounded-lg font-medium text-slate-600 hover:bg-slate-50 border border-slate-300"
              >
                Cancel
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

const SparklesIcon = ({ className }: { className?: string }) => (
  <svg xmlns="http://www.w3.org/2000/svg" className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z" />
  </svg>
);

import { S3Client, PutObjectCommand, GetObjectCommand, ListObjectsV2Command } from "@aws-sdk/client-s3";
import { Asset, AssetStatus } from '../types';

const getEnv = (key: string): string | undefined => {
  return (import.meta as any).env?.[key];
};

const REGION = getEnv('VITE_ASSET_S3_REGION') || 'us-east-1';
const BUCKET = getEnv('VITE_ASSET_S3_BUCKET');
const ACCESS_KEY = getEnv('VITE_ASSET_S3_ACCESS_KEY');
const SECRET_KEY = getEnv('VITE_ASSET_S3_SECRET_KEY');

const ASSET_PREFIX = 'assets/';

let client: S3Client | null = null;

const getClient = () => {
  if (!client) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      console.error("Missing S3 Credentials. Expected VITE_ASSET_S3_ACCESS_KEY and VITE_ASSET_S3_SECRET_KEY");
      throw new Error("S3 Credentials are not configured in environment variables.");
    }
    client = new S3Client({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
  }
  return client;
};

const getSiteFileKey = (siteId: string) => {
  const sanitized = siteId.trim().replace(/[^a-zA-Z0-9-_]/g, '_');
  return `${ASSET_PREFIX}site_${sanitized}.json`;
};

const fetchAssetsByKey = async (key: string): Promise<Asset[]> => {
  try {
    const s3 = getClient();
    const command = new GetObjectCommand({
      Bucket: BUCKET,
      Key: key,
    });

    const response = await s3.send(command);
    if (response.Body) {
      const str = await response.Body.transformToString();
      const rawData = JSON.parse(str);
      return rawData.map((item: any) => ({
        ...item,
        country: item.country || item.nation || '',
        status: item.status || item.rmaStatus || AssetStatus.Normal,
      }));
    }
    return [];
  } catch (e: any) {
