                    <td className="px-6 py-4 text-center">
                      <span className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-semibold bg-slate-100 text-slate-600 border border-slate-200">
                        {asset.siteId}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-center">
                      <div className="flex items-center justify-center gap-1.5 text-slate-600">
                        <Globe className="h-3.5 w-3.5 text-slate-400" />
                        <span className="font-medium">{asset.country || 'N/A'}</span>
                      </div>
                    </td>
                    <td className="px-6 py-4">
                      {updatingAssetId === asset.id ? (
                        <div className="flex items-center gap-2 px-2 py-1 text-xs text-blue-600 font-medium italic">
                          <Loader2 className="h-3 w-3 animate-spin" />
                          Saving...
                        </div>
                      ) : (
                        <div className="relative group/status w-fit">
                          <select
                            value={asset.status}
                            onChange={(e) => handleStatusChange(asset, e.target.value as AssetStatus)}
                            className={`
                              appearance-none cursor-pointer px-3 py-1 pr-8 rounded-full text-xs font-bold border outline-none focus:ring-2 focus:ring-blue-500/20 transition-all
                              ${getStatusColorClass(asset.status)}
                            `}
                          >
                            {Object.values(AssetStatus).map(s => (
                              <option key={s} value={s} className="bg-white text-slate-900">{s}</option>
                            ))}
                          </select>
                          <div className="absolute right-2 top-1/2 -translate-y-1/2 pointer-events-none opacity-50 group-hover/status:opacity-100 transition-opacity">
                            <svg className="h-3 w-3 fill-current" viewBox="0 0 20 20">
                              <path d="M5.293 7.293a1 1 0 011.414 0L10 10.586l3.293-3.293a1 1 0 111.414 1.414l-4 4a1 1 0 01-1.414 0l-4-4a1 1 0 010-1.414z" />
                            </svg>
                          </div>
                        </div>
                      )}
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex items-center justify-end gap-1">
                        <button
                          onClick={() => setViewingHistory(asset)}
                          className="text-slate-300 hover:text-blue-500 transition-colors p-2 rounded-md hover:bg-blue-50"
                          title="View History"
                        >
                          <HistoryIcon className="h-4 w-4" />
                        </button>
                        <button
                          onClick={() => initiateSingleDelete(asset)}
                          className="text-slate-300 hover:text-red-500 transition-colors p-2 rounded-md hover:bg-red-50"
                          title="Delete Asset"
                        >
                          <Trash2 className="h-4 w-4" />
                        </button>
                      </div>
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-500">
                    <p className="mb-2 text-lg font-medium">No assets matched your search</p>
                    <p className="text-sm">Try adjusting filters or adding new assets.</p>
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
      <div className="flex justify-between items-center text-[10px] uppercase tracking-wider font-bold text-slate-400 px-2">
         <div>
          {selectedIds.size > 0 ? `${selectedIds.size} Assets Selected` : ''}
         </div>
         <div>
           Inventory Count: {filteredAssets.length} / {assets.length}
         </div>
      </div>
    </div>
  );
};

export interface HistoryEntry {
  timestamp: number;
  field: string;
  oldValue: any;
  newValue: any;
}

export interface Asset {
  id: string;
  model: string;
  serialNumber: string;
  siteId: string;
  country: string;
  status: AssetStatus;
  createdAt: number;
  history?: HistoryEntry[];
}

export enum AssetStatus {
  Normal = 'Normal',
  RMARequested = 'RMA Requested',
  RMAShipped = 'RMA Shipped',
  RMAEligible = 'RMA Eligible',
  RMANotEligible = 'RMA Not Eligible',
  Deprecated = 'Deprecated',
  Unknown = 'Unknown'
}

export interface ParseResult {
  assets: Omit<Asset, 'id' | 'createdAt'>[];
}

import { S3Client, PutObjectCommand, GetObjectCommand, ListObjectsV2Command } from "@aws-sdk/client-s3";
import { Asset, AssetStatus, HistoryEntry } from '../types';

const getEnv = (key: string): string | undefined => {
  return (import.meta as any).env?.[key];
};

const REGION = getEnv('VITE_ASSET_S3_REGION') || 'us-east-1';
const BUCKET = getEnv('VITE_ASSET_S3_BUCKET');
const ACCESS_KEY = getEnv('VITE_ASSET_S3_ACCESS_KEY');
const SECRET_KEY = getEnv('VITE_ASSET_S3_SECRET_KEY');

const ASSET_PREFIX = 'assets/';

let client: S3Client | null = null;

const getClient = () => {
  if (!client) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      console.error("Missing S3 Credentials.");
      throw new Error("S3 Credentials are not configured.");
    }
    client = new S3Client({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
  }
  return client;
};

const getSiteFileKey = (siteId: string) => {
  const sanitized = siteId.trim().replace(/[^a-zA-Z0-9-_]/g, '_');
  return `${ASSET_PREFIX}site_${sanitized}.json`;
};

const fetchAssetsByKey = async (key: string): Promise<Asset[]> => {
  try {
    const s3 = getClient();
    const command = new GetObjectCommand({
      Bucket: BUCKET,
      Key: key,
    });

    const response = await s3.send(command);
    if (response.Body) {
      const str = await response.Body.transformToString();
      const rawData = JSON.parse(str);
      return rawData.map((item: any) => ({
        ...item,
        country: item.country || '',
        status: item.status || AssetStatus.Normal,
        history: item.history || []
      }));
    }
    return [];
  } catch (e: any) {
    if (e.name === 'NoSuchKey' || e.name === 'NotFound' || e.$metadata?.httpStatusCode === 404) {
      return [];
    }
    return [];
  }
};

export const fetchAssets = async (): Promise<Asset[]> => {
  if (!BUCKET || !ACCESS_KEY || !SECRET_KEY) return [];
  try {
    const s3 = getClient();
    const listCommand = new ListObjectsV2Command({
      Bucket: BUCKET,
      Prefix: ASSET_PREFIX,
    });
    const listResponse = await s3.send(listCommand);
    const contents = listResponse.Contents || [];
    if (contents.length === 0) return [];
    const filePromises = contents
      .map(file => file.Key)
      .filter((key): key is string => !!key)
      .map(key => fetchAssetsByKey(key));
    const results = await Promise.all(filePromises);
    return results.flat();
  } catch (e) {
    console.error('S3 Fetch Error:', e);
    throw e;
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket missing.");
  const s3 = getClient();
  const assetsBySite = newAssets.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push({
      ...asset,
      history: asset.history || [{
        timestamp: Date.now(),
        field: 'System',
        oldValue: null,
        newValue: 'Initial Asset Registration'
      }]
    });
    return acc;
  }, {} as Record<string, Asset[]>);

  const updates = Object.entries(assetsBySite).map(async ([siteId, assetsToAdd]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = [...existingAssets, ...assetsToAdd];
    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });
    return s3.send(putCommand);
  });
  await Promise.all(updates);
};

export const updateAsset = async (assetId: string, siteId: string, updates: Partial<Asset>): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket missing.");
  const s3 = getClient();
  const fileKey = getSiteFileKey(siteId);
  const existingAssets = await fetchAssetsByKey(fileKey);
  const updatedAssets = existingAssets.map(asset => {
    if (asset.id === assetId) {
      const newHistory: HistoryEntry[] = [...(asset.history || [])];
      Object.entries(updates).forEach(([key, value]) => {
        const field = key as keyof Asset;
        if (asset[field] !== value && !['history', 'id', 'createdAt'].includes(key)) {
          newHistory.push({
            timestamp: Date.now(),
            field: key,
            oldValue: asset[field],
            newValue: value
          });
        }
      });
      return { ...asset, ...updates, history: newHistory };
    }
    return asset;
  });
  const putCommand = new PutObjectCommand({
    Bucket: BUCKET,
    Key: fileKey,
    Body: JSON.stringify(updatedAssets),
    ContentType: "application/json",
  });
  await s3.send(putCommand);
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  if (!BUCKET) throw new Error("S3 Bucket missing.");
  const s3 = getClient();
  const assetsBySite = assetsToDelete.reduce((acc, asset) => {
    const key = asset.siteId;
    if (!acc[key]) acc[key] = [];
    acc[key].push(asset.id);
    return acc;
  }, {} as Record<string, string[]>);
  const updates = Object.entries(assetsBySite).map(async ([siteId, idsToDelete]) => {
    const fileKey = getSiteFileKey(siteId);
    const existingAssets = await fetchAssetsByKey(fileKey);
    const updatedAssets = existingAssets.filter(a => !idsToDelete.includes(a.id));
    const putCommand = new PutObjectCommand({
      Bucket: BUCKET,
      Key: fileKey,
      Body: JSON.stringify(updatedAssets),
      ContentType: "application/json",
    });
    return s3.send(putCommand);
  });
  await Promise.all(updates);
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Asset, AssetStatus } from '../types';
import { Search, Filter, Sparkles, Trash2, Download, Loader2, Globe, Edit3, AlertTriangle, X, History as HistoryIcon, ArrowRight } from 'lucide-react';
import { generateAssetReport } from '../services/geminiService';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateAsset: (assetId: string, siteId: string, updates: Partial<Asset>) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateAsset }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [updatingAssetId, setUpdatingAssetId] = useState<string | null>(null);

  const [editing, setEditing] = useState<{ id: string, field: 'model' | 'serialNumber', value: string } | null>(null);
  const editInputRef = useRef<HTMLInputElement>(null);
  const [assetsToDelete, setAssetsToDelete] = useState<Asset[] | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Asset | null>(null);

  useEffect(() => {
    if (editing && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select();
    }
  }, [editing]);

  const filteredAssets = useMemo(() => {
    return assets.filter(asset => {
      const matchesSearch = 
        asset.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.serialNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.siteId.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.country.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = statusFilter === 'All' || asset.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [assets, searchTerm, statusFilter]);

  const allSelected = filteredAssets.length > 0 && filteredAssets.every(a => selectedIds.has(a.id));
  const isIndeterminate = filteredAssets.some(a => selectedIds.has(a.id)) && !allSelected;

  const handleSelectAll = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newSelected = new Set(selectedIds);
    if (e.target.checked) filteredAssets.forEach(a => newSelected.add(a.id));
    else filteredAssets.forEach(a => newSelected.delete(a.id));
    setSelectedIds(newSelected);
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedIds(newSelected);
  };

  const handleStatusChange = async (asset: Asset, newStatus: AssetStatus) => {
    if (asset.status === newStatus) return;
    setUpdatingAssetId(asset.id);
    try {
      await onUpdateAsset(asset.id, asset.siteId, { status: newStatus });
    } finally {
      setUpdatingAssetId(null);
    }
  };

  const saveEdit = async () => {
    if (!editing) return;
    const asset = assets.find(a => a.id === editing.id);
    if (!asset || asset[editing.field] === editing.value) {
      setEditing(null);
      return;
    }
    setUpdatingAssetId(asset.id);
    const updates = { [editing.field]: editing.value };
    setEditing(null);
    try {
      await onUpdateAsset(asset.id, asset.siteId, updates);
    } finally {
      setUpdatingAssetId(null);
    }
  };

  const confirmDelete = () => {
    if (assetsToDelete) {
      const ids = assetsToDelete.map(a => a.id);
      onDelete(ids);
      setSelectedIds(prev => {
        const next = new Set(prev);
        ids.forEach(id => next.delete(id));
        return next;
      });
      setAssetsToDelete(null);
    }
  };

  const getStatusColor = (status: AssetStatus) => {
    switch (status) {
      case AssetStatus.Normal: return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case AssetStatus.RMARequested: return 'bg-yellow-50 text-yellow-700 border-yellow-200';
      case AssetStatus.RMAShipped: return 'bg-purple-50 text-purple-700 border-purple-200';
      case AssetStatus.RMAEligible: return 'bg-blue-50 text-blue-700 border-blue-200';
      case AssetStatus.Deprecated: return 'bg-red-50 text-red-700 border-red-200';
      default: return 'bg-slate-50 text-slate-600 border-slate-200';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Modals */}
      {assetsToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full border border-slate-200 overflow-hidden scale-100 transition-transform">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-red-600">
                <AlertTriangle className="h-6 w-6" />
                <h3 className="text-xl font-bold">Delete Assets?</h3>
              </div>
              <button onClick={() => setAssetsToDelete(null)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <div className="p-6">
              <p className="text-slate-600 mb-4">Deleting <strong>{assetsToDelete.length}</strong> asset(s) will permanently remove them from the cloud database.</p>
              <div className="max-h-40 overflow-y-auto bg-slate-50 rounded-lg p-3 space-y-2 border border-slate-200">
                {assetsToDelete.map(a => (
                  <div key={a.id} className="text-xs font-medium text-slate-700 flex justify-between">
                    <span>{a.model}</span> <span className="text-slate-400">{a.serialNumber}</span>
                  </div>
                ))}
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex gap-3">
              <button onClick={() => setAssetsToDelete(null)} className="flex-1 py-2 rounded-xl border border-slate-200 bg-white font-semibold">Cancel</button>
              <button onClick={confirmDelete} className="flex-1 py-2 rounded-xl bg-red-600 text-white font-semibold hover:bg-red-700">Confirm Delete</button>
            </div>
          </div>
        </div>
      )}

      {viewingHistory && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full border border-slate-200 flex flex-col max-h-[85vh]">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-blue-600 font-bold">
                <HistoryIcon className="h-5 w-5" />
                <span>Modification History: {viewingHistory.serialNumber}</span>
              </div>
              <button onClick={() => setViewingHistory(null)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <div className="p-6 overflow-y-auto bg-slate-50 flex-1">
              <div className="space-y-4">
                {(viewingHistory.history || []).slice().reverse().map((entry, i) => (
                  <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex justify-between text-[10px] font-bold text-slate-400 uppercase mb-2">
                      <span>{entry.field}</span>
                      <span>{new Date(entry.timestamp).toLocaleString()}</span>
                    </div>
                    {entry.oldValue === null ? (
                      <div className="text-sm text-emerald-600 font-semibold">{entry.newValue}</div>
                    ) : (
                      <div className="flex items-center gap-2 text-xs">
                        <span className="text-slate-400 line-through">{String(entry.oldValue)}</span>
                        <ArrowRight className="h-3 w-3 text-slate-300" />
                        <span className="text-blue-700 font-bold">{String(entry.newValue)}</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Table UI */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col md:flex-row gap-4 items-center justify-between">
        <div className="relative w-full md:w-80">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
          <input 
            type="text" 
            placeholder="Search assets..." 
            className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
          />
        </div>
        <div className="flex items-center gap-3 w-full md:w-auto">
          <select 
            className="px-3 py-2 border rounded-lg text-sm bg-white outline-none"
            value={statusFilter}
            onChange={e => setStatusFilter(e.target.value)}
          >
            <option value="All">All Statuses</option>
            {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          {selectedIds.size > 0 && (
            <button onClick={() => setAssetsToDelete(assets.filter(a => selectedIds.has(a.id)))} className="p-2 text-red-600 bg-red-50 border border-red-100 rounded-lg hover:bg-red-100">
              <Trash2 className="h-4 w-4" />
            </button>
          )}
          <button onClick={async () => {
            setIsAnalyzing(true);
            const r = await generateAssetReport(filteredAssets);
            setAnalysis(r);
            setIsAnalyzing(false);
          }} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-md hover:bg-indigo-700">
            {isAnalyzing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />}
            AI Insights
          </button>
        </div>
      </div>

      {analysis && (
        <div className="p-6 bg-gradient-to-br from-indigo-50 to-white rounded-2xl border border-indigo-100 shadow-sm relative animate-fade-in">
          <button onClick={() => setAnalysis(null)} className="absolute top-4 right-4 text-slate-300 hover:text-slate-500"><X className="h-4 w-4" /></button>
          <div className="prose prose-sm max-w-none text-slate-700 leading-relaxed">
            {analysis.split('\n').map((l, i) => <p key={i} className="mb-2">{l}</p>)}
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
            <tr>
              <th className="px-6 py-4 w-10 text-center">
                <input type="checkbox" checked={allSelected} ref={i => i && (i.indeterminate = isIndeterminate)} onChange={handleSelectAll} className="rounded" />
              </th>
              <th className="px-6 py-4">Model & Serial</th>
              <th className="px-6 py-4 text-center">Site & Country</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {filteredAssets.map(asset => (
              <tr key={asset.id} className={`hover:bg-slate-50/50 transition-colors ${selectedIds.has(asset.id) ? 'bg-blue-50/30' : ''}`}>
                <td className="px-6 py-4 text-center">
                  <input type="checkbox" checked={selectedIds.has(asset.id)} onChange={() => toggleSelect(asset.id)} className="rounded" />
                </td>
                <td className="px-6 py-4">
                  <div className="group/edit">
                    {editing?.id === asset.id && editing.field === 'model' ? (
                      <input ref={editInputRef} value={editing.value} onChange={e => setEditing({...editing, value: e.target.value})} onBlur={saveEdit} onKeyDown={e => e.key === 'Enter' && saveEdit()} className="border-b border-blue-500 outline-none w-full" />
                    ) : (
                      <div className="flex items-center gap-2 font-bold text-slate-900 cursor-pointer" onClick={() => setEditing({id: asset.id, field: 'model', value: asset.model})}>
                        {asset.model} <Edit3 className="h-3 w-3 opacity-0 group-hover/edit:opacity-100 text-slate-300" />
                      </div>
                    )}
                    <div className="text-[10px] font-mono text-slate-400">{asset.serialNumber}</div>
                  </div>
                </td>
                <td className="px-6 py-4 text-center">
                  <div className="font-bold text-slate-600">{asset.siteId}</div>
                  <div className="flex items-center justify-center gap-1 text-[10px] text-slate-400">
                    <Globe className="h-2 w-2" /> {asset.country}
                  </div>
                </td>
                <td className="px-6 py-4">
                  {updatingAssetId === asset.id ? <Loader2 className="h-4 w-4 animate-spin text-blue-500" /> : (
                    <select 
                      className={`px-3 py-1 rounded-full text-[10px] font-bold border ${getStatusColor(asset.status)} outline-none cursor-pointer appearance-none text-center`}
                      value={asset.status}
                      onChange={e => handleStatusChange(asset, e.target.value as AssetStatus)}
                    >
                      {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
                    </select>
                  )}
                </td>
