            ))}
            {currentItems.length === 0 && (
              <tr>
                <td colSpan={7} className="px-6 py-12 text-center text-slate-400 font-medium">
                  {totalItems > 0 ? "Adjust pagination or filters to see more results." : "No assets found matching your criteria."}
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Pagination Footer */}
        {totalItems > 0 && (
          <div className="bg-slate-50 border-t border-slate-100 px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="text-xs font-medium text-slate-500">
              Showing <span className="text-slate-900 font-bold">{startIndex + 1}</span> to <span className="text-slate-900 font-bold">{endIndex}</span> of <span className="text-slate-900 font-bold">{totalItems}</span> assets
            </div>

            <div className="flex items-center gap-1">
              <button 
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronLeft className="h-4 w-4" />
              </button>

              <div className="flex items-center gap-1 px-2">
                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                  let pageNum = i + 1;
                  // Basic slider for many pages
                  if (totalPages > 5 && currentPage > 3) {
                    pageNum = currentPage - 3 + i + 1;
                    if (pageNum > totalPages) pageNum = totalPages - (4 - i);
                  }

                  return (
                    <button
                      key={pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                      className={`min-w-[32px] h-8 text-xs font-bold rounded-lg transition-all ${
                        currentPage === pageNum 
                          ? 'bg-blue-600 text-white shadow-md shadow-blue-600/20' 
                          : 'text-slate-600 hover:bg-white hover:border-slate-300 border border-transparent'
                      }`}
                    >
                      {pageNum}
                    </button>
                  );
                })}
              </div>

              <button 
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                disabled={currentPage === totalPages}
                className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

import { DynamoDBClient } from "@aws-sdk/client-dynamodb";
import { 
  DynamoDBDocumentClient, 
  ScanCommand, 
  PutCommand, 
  UpdateCommand, 
  DeleteCommand,
  BatchWriteCommand
} from "@aws-sdk/lib-dynamodb";
import { Asset, AssetStatus, HistoryEntry } from '../types';

const getEnv = (key: string): string | undefined => {
  return (import.meta as any).env?.[key];
};

const REGION = getEnv('VITE_ASSET_AWS_REGION') || 'us-east-1';
const TABLE_NAME = getEnv('VITE_ASSET_DYNAMO_TABLE') || 'Assets';
const ACCESS_KEY = getEnv('VITE_ASSET_S3_ACCESS_KEY');
const SECRET_KEY = getEnv('VITE_ASSET_S3_SECRET_KEY');

let docClient: DynamoDBDocumentClient | null = null;

const getDocClient = () => {
  if (!docClient) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      console.error("Missing AWS Credentials for DynamoDB.");
      throw new Error("AWS Credentials are not configured.");
    }
    const client = new DynamoDBClient({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
    docClient = DynamoDBDocumentClient.from(client, {
      marshallOptions: {
        removeUndefinedValues: true,
        convertEmptyStrings: true,
      }
    });
  }
  return docClient;
};

export const fetchAssets = async (): Promise<Asset[]> => {
  if (!ACCESS_KEY || !SECRET_KEY) return [];
  try {
    const client = getDocClient();
    const command = new ScanCommand({
      TableName: TABLE_NAME,
    });

    const response = await client.send(command);
    const items = response.Items || [];

    return items.map((item: any) => ({
      ...item,
      country: item.country || '',
      status: item.status || AssetStatus.Normal,
      history: item.history || []
    })) as Asset[];
  } catch (e) {
    console.error('DynamoDB Fetch Error:', e);
    throw e;
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  const client = getDocClient();

  // Prepare batch write (max 25 items per batch for DynamoDB)
  const batches: Asset[][] = [];
  for (let i = 0; i < newAssets.length; i += 25) {
    batches.push(newAssets.slice(i, i + 25));
  }

  const writePromises = batches.map(async (batch) => {
    const putRequests = batch.map(asset => ({
      PutRequest: {
        Item: {
          ...asset,
          history: asset.history || [{
            timestamp: Date.now(),
            field: 'System',
            oldValue: null,
            newValue: 'Initial Asset Registration'
          }]
        }
      }
    }));

    const command = new BatchWriteCommand({
      RequestItems: {
        [TABLE_NAME]: putRequests
      }
    });
    return client.send(command);
  });

  await Promise.all(writePromises);
};

export const updateAsset = async (assetId: string, siteId: string, updates: Partial<Asset>): Promise<void> => {
  const client = getDocClient();

  // To update history, we first need to fetch the current asset to compare values
  // Alternatively, we can use a more complex UpdateExpression, but fetching first is safer for history logging
  const currentAssets = await fetchAssets(); 
  const asset = currentAssets.find(a => a.id === assetId && a.siteId === siteId);

  if (!asset) throw new Error("Asset not found for update.");

  const newHistory: HistoryEntry[] = [...(asset.history || [])];
  Object.entries(updates).forEach(([key, value]) => {
    const field = key as keyof Asset;
    if (asset[field] !== value && !['history', 'id', 'createdAt'].includes(key)) {
      newHistory.push({
        timestamp: Date.now(),
        field: key,
        oldValue: asset[field],
        newValue: value
      });
    }
  });

  const updatedAsset = { ...asset, ...updates, history: newHistory };

  const command = new PutCommand({
    TableName: TABLE_NAME,
    Item: updatedAsset
  });

  await client.send(command);
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  const client = getDocClient();

  const batches: Asset[][] = [];
  for (let i = 0; i < assetsToDelete.length; i += 25) {
    batches.push(assetsToDelete.slice(i, i + 25));
  }

  const deletePromises = batches.map(async (batch) => {
    const deleteRequests = batch.map(asset => ({
      DeleteRequest: {
        Key: {
          siteId: asset.siteId,
          id: asset.id
        }
      }
    }));

    const command = new BatchWriteCommand({
      RequestItems: {
        [TABLE_NAME]: deleteRequests
      }
    });
    return client.send(command);
  });

  await Promise.all(deletePromises);
};

import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AssetList } from './components/AssetList';
import { AssetForm } from './components/AssetForm';
import { Login } from './components/Login';
import { Asset } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAsset } from './services/storageService';
import { Loader2, Database as DbIcon, DatabaseZap, ShieldCheck, PlusCircle } from 'lucide-react';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('portal_auth') === 'true';
  });
  const [view, setView] = useState<'list' | 'add'>('list');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => {
    if (isAuthenticated) {
      loadData();
    }
  }, [isAuthenticated]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
    } catch (error) {
      console.error(error);
      setIsConnected(false);
      showNotification('DynamoDB Connection failed. Verify IAM permissions.', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (user: string, pass: string): Promise<boolean> => {
    const validUser = (import.meta as any).env?.VITE_PORTAL_USERNAME || 'admin';
    const validPass = (import.meta as any).env?.VITE_PORTAL_PASSWORD || 'password123';

    if (user === validUser && pass === validPass) {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    sessionStorage.removeItem('portal_auth');
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error) {
      console.error(error);
      showNotification('Save failed. Check DynamoDB Table Name/Region.', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdateAsset = async (assetId: string, siteId: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(assetId, siteId, updates);
      setAssets(prev => prev.map(a => a.id === assetId ? { ...a, ...updates } : a));
      showNotification('Asset updated in DynamoDB', 'success');
    } catch (error) {
      console.error(error);
      showNotification('Update failed.', 'error');
      throw error; 
    }
  };

  const handleDeleteAssets = async (ids: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => ids.includes(a.id));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !ids.includes(a.id)));
      showNotification('Assets removed from DynamoDB', 'success');
    } catch (error) {
      console.error(error);
      showNotification('Delete failed.', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const tableName = (import.meta as any).env?.VITE_ASSET_DYNAMO_TABLE || 'Assets';
  const regionName = (import.meta as any).env?.VITE_ASSET_AWS_REGION || 'us-east-1';

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  if (isLoading && assets.length === 0 && isConnected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <div className="loader ease-linear rounded-full border-4 border-t-4 border-slate-200 h-12 w-12 mb-4"></div>
        <p className="text-slate-500 font-medium">Connecting to DynamoDB Instance...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentView={view} 
        onNavigate={setView} 
        onLogout={handleLogout} 
      />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8 relative">

        <div className="mb-4 flex justify-end items-center">
          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider border shadow-sm ${
            isConnected 
              ? 'bg-blue-50 text-blue-700 border-blue-200' 
              : isConnected === false 
                ? 'bg-red-50 text-red-700 border-red-200'
                : 'bg-slate-50 text-slate-500 border-slate-200'
          }`}>
            {isConnected ? <DatabaseZap className="h-3 w-3" /> : <DbIcon className="h-3 w-3" />}
            {isConnected ? 'DynamoDB Active' : 'No Connection'}
            {isConnected && <ShieldCheck className="h-3 w-3 ml-1" />}
          </div>
        </div>

        {isSaving && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-sm z-[200] flex items-center justify-center">
             <div className="bg-white px-8 py-6 rounded-2xl shadow-2xl flex flex-col items-center gap-4 border border-slate-100 animate-fade-in">
                <div className="bg-blue-50 p-3 rounded-full">
                  <Loader2 className="h-6 w-6 animate-spin text-blue-600" />
                </div>
                <div className="text-center">
                  <h3 className="font-bold text-slate-900">Committing Changes</h3>
                  <p className="text-xs text-slate-500 mt-1">Updating secure AWS DynamoDB table...</p>
                </div>
             </div>
          </div>
        )}

        {notification && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-2xl shadow-2xl z-50 animate-fade-in flex items-center gap-3 border ${
            notification.type === 'success' 
              ? 'bg-white text-emerald-700 border-emerald-100' 
              : 'bg-white text-red-700 border-red-100'
          }`}>
            {notification.type === 'success' ? <ShieldCheck className="h-5 w-5" /> : <DbIcon className="h-5 w-5" />}
            <span className="font-bold text-sm tracking-tight">{notification.message}</span>
          </div>
        )}

        {view === 'list' ? (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Inventory</h2>
                <div className="flex items-center gap-2 mt-1.5">
                  <span className="text-sm font-medium text-slate-400">Database:</span>
                  <code className="text-[10px] font-bold bg-slate-100 px-1.5 py-0.5 rounded text-slate-600">{tableName}</code>
                </div>
              </div>
              <button
                onClick={() => setView('add')}
                className="bg-blue-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-600/20 active:scale-95 flex items-center justify-center gap-2"
              >
                <PlusCircle className="h-4 w-4" />
                Register Asset
              </button>
            </div>
            <AssetList 
              assets={assets} 
              onDelete={handleDeleteAssets} 
              onUpdateAsset={handleUpdateAsset}
            />
          </div>
        ) : (
          <div className="space-y-8 max-w-4xl mx-auto">
            <div className="text-center">
              <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Add New Assets</h2>
              <p className="text-slate-500 mt-2 font-medium">Manual entry, bulk upload, or Gemini AI extraction.</p>
            </div>
            <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center gap-4 text-slate-400 text-xs">
          <div className="font-bold uppercase tracking-widest">&copy; {new Date().getFullYear()} EU_EF IT ASSET PORTAL</div>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-blue-500' : 'bg-red-500'}`}></div>
              <span className="font-semibold">{regionName.toUpperCase()}</span>
            </div>
            <div className="h-4 w-px bg-slate-200"></div>
            <div className="font-mono opacity-60">v1.4-DYNAMODB</div>
          </div>
        </div>
      </footer>
    </div>
  );
}

