export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  try {
    const client = getDocClient();
    const batches: Asset[][] = [];
    for (let i = 0; i < assetsToDelete.length; i += 25) {
      batches.push(assetsToDelete.slice(i, i + 25));
    }

    const deletePromises = batches.map(async (batch) => {
      const deleteRequests = batch.map(asset => ({
        DeleteRequest: {
          // IMPORTANT: Only provide the actual Partition Key defined in AWS. 
          // If your table has a Sort Key, you must add it here too.
          Key: {
            id: asset.id
          }
        }
      }));

      const command = new BatchWriteCommand({
        RequestItems: {
          [TABLE_NAME]: deleteRequests
        }
      });
      return client.send(command);
    });

    await Promise.all(deletePromises);
  } catch (e: any) {
    console.error('Delete Error:', e);
    if (e.message.includes('key element')) {
       throw new Error("Delete Failed: The identifier provided doesn't match your DynamoDB Table Key schema.");
    }
    throw e;
  }
};

import { useState, useRef } from 'react';
import { Asset, AssetStatus } from '../types';
import { parseAssetsFromText } from '../services/geminiService';
import { Bot, Save, AlertCircle, CheckCircle, Upload, FileSpreadsheet, Download, X } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetFormProps {
  onAddAssets: (assets: Asset[]) => void;
  onCancel: () => void;
}

export const AssetForm: React.FC<AssetFormProps> = ({ onAddAssets, onCancel }) => {
  const [mode, setMode] = useState<'manual' | 'ai' | 'bulk'>('manual');

  // Manual State
  const [manualForm, setManualForm] = useState({
    model: '',
    serialNumber: '',
    siteId: '',
    country: '',
    status: AssetStatus.Normal
  });

  // AI State
  const [aiInput, setAiInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // Bulk State
  const [bulkPreview, setBulkPreview] = useState<Asset[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.model || !manualForm.serialNumber || !manualForm.siteId || !manualForm.country) {
      setError("Please fill in all required fields.");
      return;
    }

    const newAsset: Asset = {
      id: uuidv4(),
      ...manualForm,
      createdAt: Date.now()
    };

    onAddAssets([newAsset]);
  };

  const handleAiParse = async () => {
    if (!aiInput.trim()) return;

    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parseAssetsFromText(aiInput);

      if (parsedData.length === 0) {
        setError("AI couldn't find any assets in the text. Try rephrasing or use manual entry.");
      } else {
        const newAssets: Asset[] = parsedData.map(p => ({
          id: uuidv4(),
          model: p.model || 'Unknown',
          serialNumber: p.serialNumber || 'Unknown',
          siteId: p.siteId || 'Unknown',
          country: p.country || '',
          status: (p.status as AssetStatus) || AssetStatus.Normal,
          createdAt: Date.now()
        }));
        onAddAssets(newAssets);
      }
    } catch (err) {
      setError("Failed to process text. Check your API connection.");
    } finally {
      setIsProcessing(false);
    }
  };

  const processRowToAsset = (row: any): Asset | null => {
    const normalizedRow: Record<string, any> = {};
    Object.keys(row).forEach(key => {
      normalizedRow[key.toLowerCase().trim().replace(/[^a-z0-9]/g, '')] = row[key];
    });

    // Flexible mapping for common IT headers
    const model = normalizedRow['model'] || normalizedRow['assetmodel'] || normalizedRow['product'] || normalizedRow['device'] || normalizedRow['item'];
    const serial = normalizedRow['serialnumber'] || normalizedRow['serial'] || normalizedRow['sn'] || normalizedRow['serialno'] || normalizedRow['snno'];
    const site = normalizedRow['siteid'] || normalizedRow['site'] || normalizedRow['location'] || normalizedRow['sitecode'];
    const country = normalizedRow['country'] || normalizedRow['nation'] || normalizedRow['origin'] || normalizedRow['region'];
    const status = normalizedRow['status'] || normalizedRow['rmastatus'] || normalizedRow['rma'] || normalizedRow['condition'];

    if (model && serial && site) {
      let assetStatus = AssetStatus.Normal;
      if (status) {
        const s = String(status).trim();
        const foundStatus = Object.values(AssetStatus).find(
          enumVal => enumVal.toLowerCase() === s.toLowerCase()
        );
        if (foundStatus) {
          assetStatus = foundStatus;
        } else if (s.toLowerCase().includes('request')) {
          assetStatus = AssetStatus.RMARequested;
        } else if (s.toLowerCase().includes('ship')) {
          assetStatus = AssetStatus.RMAShipped;
        } else if (s.toLowerCase().includes('not eligible')) {
          assetStatus = AssetStatus.RMANotEligible;
        } else if (s.toLowerCase().includes('eligible')) {
          assetStatus = AssetStatus.RMAEligible;
        } else if (s.toLowerCase().includes('deprecated')) {
          assetStatus = AssetStatus.Deprecated;
        } else {
          assetStatus = AssetStatus.Unknown;
        }
      }

      return {
        id: uuidv4(),
        model: String(model).trim(),
        serialNumber: String(serial).trim(),
        siteId: String(site).trim(),
        country: country ? String(country).trim() : '',
        status: assetStatus,
        createdAt: Date.now()
      };
    }
    return null;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const fileExt = file.name.split('.').pop()?.toLowerCase();

    if (fileExt === 'csv') {
      Papa.parse(file, {
        header: true,
        skipEmptyLines: true,
        complete: (results) => {
          const assets: Asset[] = results.data
            .map(row => processRowToAsset(row))
            .filter((a): a is Asset => a !== null);

          if (assets.length === 0) {
            setError("No valid assets found in CSV. Required columns: Model, Serial Number, Site ID.");
          } else {
            setBulkPreview(assets);
            setError(null);
          }
        },
        error: (err) => {
          setError(`Failed to parse CSV: ${err.message}`);
        }
      });
    } else if (fileExt === 'xlsx' || fileExt === 'xls') {
      const reader = new FileReader();
      reader.onload = (evt) => {
        try {
          const bstr = evt.target?.result;
          const wb = XLSX.read(bstr, { type: 'binary' });
          const wsname = wb.SheetNames[0];
          const ws = wb.Sheets[wsname];
          const data = XLSX.utils.sheet_to_json(ws);

          const assets: Asset[] = data
            .map(row => processRowToAsset(row))
            .filter((a): a is Asset => a !== null);

          if (assets.length === 0) {
            setError("No valid assets found in Excel. Ensure you have columns like Model, Serial, Site ID.");
          } else {
            setBulkPreview(assets);
            setError(null);
          }
        } catch (err: any) {
          setError(`Failed to parse Excel: ${err.message}`);
        }
      };
      reader.readAsBinaryString(file);
    } else {
      setError("Unsupported format. Use .csv, .xlsx, or .xls");
    }

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  const downloadTemplate = () => {
    const csvContent = "Model,Serial Number,SiteID,Country,Status\nCisco C9200,FOC12345678,NYC-01,USA,Normal\nLenovo X1,PF123456,LON-HQ,UK,RMA Requested";
    const blob = new Blob([csvContent], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = "asset_template.csv";
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    window.URL.revokeObjectURL(url);
  };

  const confirmBulkUpload = () => {
    onAddAssets(bulkPreview);
    setBulkPreview([]);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex flex-wrap gap-2 md:gap-4 p-1 bg-slate-100 rounded-lg w-full md:w-fit mx-auto justify-center">
        <button
          onClick={() => setMode('manual')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all ${
            mode === 'manual' 
              ? 'bg-white text-blue-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          Manual Entry
        </button>
        <button
          onClick={() => setMode('bulk')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'bulk' 
              ? 'bg-white text-emerald-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <FileSpreadsheet className="h-4 w-4" />
          Bulk Upload (Excel/CSV)
        </button>
        <button
          onClick={() => setMode('ai')}
          className={`flex-1 md:flex-none px-4 py-2 rounded-md text-sm font-medium transition-all flex items-center justify-center gap-2 ${
            mode === 'ai' 
              ? 'bg-white text-purple-700 shadow-sm' 
              : 'text-slate-600 hover:text-slate-900'
          }`}
        >
          <Bot className="h-4 w-4" />
          AI Import
        </button>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-6 md:p-8">
        {error && (
          <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2 text-sm border border-red-100">
            <AlertCircle className="h-5 w-5 flex-shrink-0" />
            {error}
          </div>
        )}

        {mode === 'manual' && (
          <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <label className="block text-sm font-medium text-slate-700 mb-2">Asset Model *</label>
                <input
                  type="text"
                  required
                  className="w-full px-4 py-2 border border-slate-300 rounded-lg focus:ring-2 focus:ring-blue-500 outline-none"
                  value={manualForm.model}
