import { Asset } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAsset } from './services/storageService';
import { Loader2, Database as DbIcon, DatabaseZap, ShieldCheck, PlusCircle, AlertCircle } from 'lucide-react';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return sessionStorage.getItem('portal_auth') === 'true';
  });
  const [view, setView] = useState<'list' | 'add'>('list');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => {
    if (isAuthenticated) {
      loadData();
    }
  }, [isAuthenticated]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
    } catch (error: any) {
      console.error(error);
      setIsConnected(false);
      showNotification(error.message || 'DynamoDB Connection failed.', 'error');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (user: string, pass: string): Promise<boolean> => {
    const validUser = (import.meta as any).env?.VITE_PORTAL_USERNAME || 'admin';
    const validPass = (import.meta as any).env?.VITE_PORTAL_PASSWORD || 'password123';

    if (user === validUser && pass === validPass) {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAuthenticated(false);
    sessionStorage.removeItem('portal_auth');
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    const duration = type === 'error' ? 8000 : 5000;
    setTimeout(() => setNotification(null), duration);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error: any) {
      console.error(error);
      showNotification(error.message || 'Save failed.', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleUpdateAsset = async (assetId: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(assetId, updates);
      setAssets(prev => prev.map(a => a.id === assetId ? { ...a, ...updates } : a));
      showNotification('Asset updated in DynamoDB', 'success');
    } catch (error: any) {
      console.error(error);
      showNotification(error.message || 'Update failed.', 'error');
      throw error; 
    }
  };

  const handleDeleteAssets = async (ids: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => ids.includes(a.id));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !ids.includes(a.id)));
      showNotification('Assets removed from DynamoDB', 'success');
    } catch (error: any) {
      console.error(error);
      showNotification(error.message || 'Delete failed.', 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const tableName = (import.meta as any).env?.VITE_ASSET_DYNAMO_TABLE || 'Assets';
  const regionName = (import.meta as any).env?.VITE_ASSET_AWS_REGION || 'us-east-1';

  if (!isAuthenticated) {
    return <Login onLogin={handleLogin} />;
  }

  if (isLoading && assets.length === 0 && isConnected === null) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center">
        <div className="loader ease-linear rounded-full border-4 border-t-4 border-slate-200 h-12 w-12 mb-4"></div>
        <p className="text-slate-500 font-medium">Connecting to DynamoDB Instance...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      <Header 
        currentView={view} 
        onNavigate={setView} 
        onLogout={handleLogout} 
      />

      <main className="flex-1 max-w-7xl w-full mx-auto px-4 sm:px-6 lg:px-8 py-8 relative">

        <div className="mb-4 flex justify-end items-center">
          <div className={`flex items-center gap-2 px-3 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-wider border shadow-sm ${
            isConnected 
              ? 'bg-blue-50 text-blue-700 border-blue-200' 
              : isConnected === false 
                ? 'bg-red-50 text-red-700 border-red-200'
                : 'bg-slate-50 text-slate-500 border-slate-200'
          }`}>
            {isConnected ? <DatabaseZap className="h-3 w-3" /> : <DbIcon className="h-3 w-3" />}
            {isConnected ? 'DynamoDB Active' : 'No Connection'}
            {isConnected && <ShieldCheck className="h-3 w-3 ml-1" />}
          </div>
        </div>

        {isSaving && (
          <div className="fixed inset-0 bg-slate-900/10 backdrop-blur-sm z-[200] flex items-center justify-center">
             <div className="bg-white px-8 py-6 rounded-2xl shadow-2xl flex flex-col items-center gap-4 border border-slate-100 animate-fade-in">
                <div className="bg-blue-50 p-3 rounded-full">
                  <Loader2 className="h-6 w-6 animate-spin text-blue-600" />
                </div>
                <div className="text-center">
                  <h3 className="font-bold text-slate-900">Synchronizing Data</h3>
                  <p className="text-xs text-slate-500 mt-1">AWS Cloud Operations in progress...</p>
                </div>
             </div>
          </div>
        )}

        {notification && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-2xl shadow-2xl z-50 animate-fade-in flex items-center gap-3 border max-w-[90vw] md:max-w-md ${
            notification.type === 'success' 
              ? 'bg-white text-emerald-700 border-emerald-100' 
              : 'bg-white text-red-700 border-red-100'
          }`}>
            {notification.type === 'success' ? <ShieldCheck className="h-5 w-5 flex-shrink-0" /> : <AlertCircle className="h-5 w-5 flex-shrink-0" />}
            <span className="font-bold text-xs tracking-tight">{notification.message}</span>
          </div>
        )}

        {view === 'list' ? (
          <div className="space-y-6">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Inventory</h2>
                <div className="flex items-center gap-2 mt-1.5">
                  <span className="text-sm font-medium text-slate-400">Database:</span>
                  <code className="text-[10px] font-bold bg-slate-100 px-1.5 py-0.5 rounded text-slate-600">{tableName}</code>
                </div>
              </div>
              <button
                onClick={() => setView('add')}
                className="bg-blue-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-blue-700 transition-all shadow-lg shadow-blue-600/20 active:scale-95 flex items-center justify-center gap-2"
              >
                <PlusCircle className="h-4 w-4" />
                Register Asset
              </button>
            </div>
            <AssetList 
              assets={assets} 
              onDelete={handleDeleteAssets} 
              onUpdateAsset={handleUpdateAsset}
            />
          </div>
        ) : (
          <div className="space-y-8 max-w-4xl mx-auto">
            <div className="text-center">
              <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Add New Assets</h2>
              <p className="text-slate-500 mt-2 font-medium">Manual entry, bulk upload, or Gemini AI extraction.</p>
            </div>
            <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />
          </div>
        )}
      </main>

      <footer className="bg-white border-t border-slate-200 py-8 mt-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 flex flex-col md:flex-row justify-between items-center gap-4 text-slate-400 text-xs">
          <div className="font-bold uppercase tracking-widest">&copy; {new Date().getFullYear()} EU_EF IT ASSET PORTAL</div>
          <div className="flex items-center gap-6">
            <div className="flex items-center gap-2">
              <div className={`w-2 h-2 rounded-full ${isConnected ? 'bg-blue-500' : 'bg-red-500'}`}></div>
              <span className="font-semibold">{regionName.toUpperCase()}</span>
            </div>
            <div className="h-4 w-px bg-slate-200"></div>
            <div className="font-mono opacity-60">v1.4-DYNAMODB</div>
          </div>
        </div>
      </footer>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Asset, AssetStatus } from '../types';
import { Search, Sparkles, Trash2, Loader2, Globe, Edit3, AlertTriangle, X, History as HistoryIcon, ArrowRight, Hash, ChevronLeft, ChevronRight } from 'lucide-react';
import { generateAssetReport } from '../services/geminiService';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateAsset: (assetId: string, updates: Partial<Asset>) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateAsset }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedIds, setSelectedIds] = useState<Set<string>>(new Set());
  const [updatingAssetId, setUpdatingAssetId] = useState<string | null>(null);

  // Pagination State
  const [itemsPerPage, setItemsPerPage] = useState<number>(25);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [editing, setEditing] = useState<{ id: string, field: 'model' | 'serialNumber', value: string } | null>(null);
  const editInputRef = useRef<HTMLInputElement>(null);
  const [assetsToDelete, setAssetsToDelete] = useState<Asset[] | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Asset | null>(null);

  useEffect(() => {
    if (editing && editInputRef.current) {
      editInputRef.current.focus();
      editInputRef.current.select();
    }
  }, [editing]);

  // Reset page when filters change
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter, itemsPerPage]);

  const filteredAssets = useMemo(() => {
    return assets.filter(asset => {
      const matchesSearch = 
        asset.model.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.serialNumber.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.siteId.toLowerCase().includes(searchTerm.toLowerCase()) ||
        asset.country.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesStatus = statusFilter === 'All' || asset.status === statusFilter;
      return matchesSearch && matchesStatus;
    });
  }, [assets, searchTerm, statusFilter]);

  // Pagination Logic
  const totalItems = filteredAssets.length;
  const totalPages = Math.ceil(totalItems / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const endIndex = Math.min(startIndex + itemsPerPage, totalItems);
  const currentItems = filteredAssets.slice(startIndex, endIndex);

  const allSelectedOnPage = currentItems.length > 0 && currentItems.every(a => selectedIds.has(a.id));
  const isIndeterminateOnPage = currentItems.some(a => selectedIds.has(a.id)) && !allSelectedOnPage;

  const handleSelectAllOnPage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newSelected = new Set(selectedIds);
    if (e.target.checked) currentItems.forEach(a => newSelected.add(a.id));
    else currentItems.forEach(a => newSelected.delete(a.id));
    setSelectedIds(newSelected);
  };

  const toggleSelect = (id: string) => {
    const newSelected = new Set(selectedIds);
    if (newSelected.has(id)) newSelected.delete(id);
    else newSelected.add(id);
    setSelectedIds(newSelected);
  };

  const handleStatusChange = async (asset: Asset, newStatus: AssetStatus) => {
    if (asset.status === newStatus) return;
    setUpdatingAssetId(asset.id);
    try {
      await onUpdateAsset(asset.id, { status: newStatus });
    } finally {
      setUpdatingAssetId(null);
    }
  };

  const saveEdit = async () => {
    if (!editing) return;
    const asset = assets.find(a => a.id === editing.id);
    if (!asset || asset[editing.field] === editing.value) {
      setEditing(null);
      return;
    }
    setUpdatingAssetId(asset.id);
    const updates = { [editing.field]: editing.value };
    setEditing(null);
    try {
      await onUpdateAsset(asset.id, updates);
    } finally {
      setUpdatingAssetId(null);
    }
  };

  const confirmDelete = () => {
    if (assetsToDelete) {
      const ids = assetsToDelete.map(a => a.id);
      onDelete(ids);
      setSelectedIds(prev => {
        const next = new Set(prev);
        ids.forEach(id => next.delete(id));
        return next;
      });
      setAssetsToDelete(null);
    }
  };

  const getStatusColor = (status: AssetStatus) => {
    switch (status) {
      case AssetStatus.Normal: return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case AssetStatus.RMARequested: return 'bg-yellow-50 text-yellow-700 border-yellow-200';
      case AssetStatus.RMAShipped: return 'bg-purple-50 text-purple-700 border-purple-200';
      case AssetStatus.RMAEligible: return 'bg-blue-50 text-blue-700 border-blue-200';
      case AssetStatus.Deprecated: return 'bg-red-50 text-red-700 border-red-200';
      default: return 'bg-slate-50 text-slate-600 border-slate-200';
    }
  };

  return (
    <div className="space-y-6 animate-fade-in">
      {/* Modals */}
      {assetsToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-lg w-full border border-slate-200 overflow-hidden scale-100 transition-transform">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-red-600">
                <AlertTriangle className="h-6 w-6" />
                <h3 className="text-xl font-bold">Delete Assets?</h3>
              </div>
              <button onClick={() => setAssetsToDelete(null)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <div className="p-6">
              <p className="text-slate-600 mb-4">Deleting <strong>{assetsToDelete.length}</strong> asset(s) will permanently remove them from the cloud database.</p>
              <div className="max-h-40 overflow-y-auto bg-slate-50 rounded-lg p-3 space-y-2 border border-slate-200">
                {assetsToDelete.map(a => (
                  <div key={a.id} className="text-xs font-medium text-slate-700 flex justify-between">
                    <span>{a.model}</span> <span className="text-slate-400">{a.serialNumber}</span>
                  </div>
                ))}
              </div>
            </div>
            <div className="p-6 bg-slate-50 flex gap-3">
              <button onClick={() => setAssetsToDelete(null)} className="flex-1 py-2 rounded-xl border border-slate-200 bg-white font-semibold">Cancel</button>
              <button onClick={confirmDelete} className="flex-1 py-2 rounded-xl bg-red-600 text-white font-semibold hover:bg-red-700">Confirm Delete</button>
            </div>
          </div>
        </div>
      )}

      {viewingHistory && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl shadow-2xl max-w-2xl w-full border border-slate-200 flex flex-col max-h-[85vh]">
            <div className="p-6 border-b border-slate-100 flex items-center justify-between">
              <div className="flex items-center gap-3 text-blue-600 font-bold">
                <HistoryIcon className="h-5 w-5" />
                <span>Modification History: {viewingHistory.serialNumber}</span>
              </div>
              <button onClick={() => setViewingHistory(null)} className="text-slate-400 hover:text-slate-600"><X /></button>
            </div>
            <div className="p-6 overflow-y-auto bg-slate-50 flex-1">
              <div className="space-y-4">
                {(viewingHistory.history || []).slice().reverse().map((entry, i) => (
                  <div key={i} className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm">
                    <div className="flex justify-between text-[10px] font-bold text-slate-400 uppercase mb-2">
                      <span>{entry.field}</span>
                      <span>{new Date(entry.timestamp).toLocaleString()}</span>
                    </div>
                    {entry.oldValue === null ? (
                      <div className="text-sm text-emerald-600 font-semibold">{entry.newValue}</div>
                    ) : (
                      <div className="flex items-center gap-2 text-xs">
                        <span className="text-slate-400 line-through">{String(entry.oldValue)}</span>
                        <ArrowRight className="h-3 w-3 text-slate-300" />
                        <span className="text-blue-700 font-bold">{String(entry.newValue)}</span>
                      </div>
                    )}
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Table UI Controls */}
      <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm flex flex-col lg:flex-row gap-4 items-center justify-between">
        <div className="flex flex-col sm:flex-row gap-4 w-full lg:w-auto items-center">
          <div className="relative w-full sm:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search by model, SN, site or country..." 
              className="w-full pl-10 pr-4 py-2 border rounded-lg outline-none focus:ring-2 focus:ring-blue-500 text-sm"
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex items-center gap-2 w-full sm:w-auto">
            <label className="text-xs font-bold text-slate-400 uppercase tracking-wider whitespace-nowrap">View:</label>
            <select 
              className="px-3 py-2 border rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500"
              value={itemsPerPage}
              onChange={e => setItemsPerPage(Number(e.target.value))}
            >
              {[25, 50, 100, 125, 150].map(val => (
                <option key={val} value={val}>{val} per page</option>
              ))}
            </select>
          </div>
        </div>

        <div className="flex items-center gap-3 w-full lg:w-auto justify-end">
          <select 
            className="px-3 py-2 border rounded-lg text-sm bg-white outline-none focus:ring-2 focus:ring-blue-500"
            value={statusFilter}
            onChange={e => setStatusFilter(e.target.value)}
          >
            <option value="All">All Statuses</option>
            {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
          </select>
          {selectedIds.size > 0 && (
            <button onClick={() => setAssetsToDelete(assets.filter(a => selectedIds.has(a.id)))} className="p-2 text-red-600 bg-red-50 border border-red-100 rounded-lg hover:bg-red-100 transition-colors">
              <Trash2 className="h-4 w-4" />
            </button>
          )}
          <button onClick={async () => {
            setIsAnalyzing(true);
            try {
              const r = await generateAssetReport(filteredAssets);
              setAnalysis(r);
            } finally {
              setIsAnalyzing(false);
            }
          }} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold shadow-md hover:bg-indigo-700 transition-all active:scale-95">
            {isAnalyzing ? <Loader2 className="h-4 w-4 animate-spin" /> : <Sparkles className="h-4 w-4" />}
            AI Insights
          </button>
        </div>
      </div>

      {analysis && (
        <div className="p-6 bg-gradient-to-br from-indigo-50 to-white rounded-2xl border border-indigo-100 shadow-sm relative animate-fade-in">
          <button onClick={() => setAnalysis(null)} className="absolute top-4 right-4 text-slate-300 hover:text-slate-500 transition-colors"><X className="h-4 w-4" /></button>
          <div className="prose prose-sm max-w-none text-slate-700 leading-relaxed">
            {analysis.split('\n').map((l, i) => <p key={i} className="mb-2">{l}</p>)}
          </div>
        </div>
      )}

      <div className="bg-white rounded-2xl border border-slate-200 shadow-sm overflow-hidden overflow-x-auto flex flex-col">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50 border-b border-slate-100 text-slate-500 font-bold uppercase text-[10px] tracking-wider">
            <tr>
              <th className="px-6 py-4 w-10 text-center">
                <input 
                  type="checkbox" 
                  checked={allSelectedOnPage} 
                  ref={el => { if (el) { el.indeterminate = isIndeterminateOnPage; } }} 
                  onChange={handleSelectAllOnPage} 
                  className="rounded border-slate-300 text-blue-600 focus:ring-blue-500" 
                />
              </th>
              <th className="px-6 py-4">Model</th>
              <th className="px-6 py-4">Serial Number</th>
              <th className="px-6 py-4">Site ID</th>
              <th className="px-6 py-4">Country</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {currentItems.map(asset => (
              <tr key={asset.id} className={`hover:bg-slate-50/50 transition-colors ${selectedIds.has(asset.id) ? 'bg-blue-50/30' : ''}`}>
                <td className="px-6 py-4 text-center">
                  <input 
                    type="checkbox" 
                    checked={selectedIds.has(asset.id)} 
                    onChange={() => toggleSelect(asset.id)} 
                    className="rounded border-slate-300 text-blue-600 focus:ring-blue-500" 
                  />
                </td>
                <td className="px-6 py-4">
                  <div className="group/edit">
                    {editing?.id === asset.id && editing.field === 'model' ? (
                      <input 
                        ref={editInputRef} 
                        value={editing.value} 
                        onChange={e => setEditing({...editing, value: e.target.value})} 
                        onBlur={saveEdit} 
                        onKeyDown={e => e.key === 'Enter' && saveEdit()} 
                        className="border-b border-blue-500 outline-none w-full bg-transparent font-bold text-slate-900" 
                      />
                    ) : (
                      <div className="flex items-center gap-2 font-bold text-slate-900 cursor-pointer" onClick={() => setEditing({id: asset.id, field: 'model', value: asset.model})}>
                        {asset.model} <Edit3 className="h-3 w-3 opacity-0 group-hover/edit:opacity-100 text-slate-300 transition-opacity" />
                      </div>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="group/edit">
                    {editing?.id === asset.id && editing.field === 'serialNumber' ? (
                      <input 
                        ref={editInputRef} 
                        value={editing.value} 
                        onChange={e => setEditing({...editing, value: e.target.value})} 
                        onBlur={saveEdit} 
                        onKeyDown={e => e.key === 'Enter' && saveEdit()} 
                        className="border-b border-blue-500 outline-none w-full bg-transparent font-mono text-xs text-slate-600" 
                      />
                    ) : (
                      <div className="flex items-center gap-2 font-mono text-xs text-slate-600 cursor-pointer" onClick={() => setEditing({id: asset.id, field: 'serialNumber', value: asset.serialNumber})}>
                        <Hash className="h-3 w-3 text-slate-300" />
                        {asset.serialNumber} 
                        <Edit3 className="h-3 w-3 opacity-0 group-hover/edit:opacity-100 text-slate-300 transition-opacity" />
                      </div>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="font-semibold text-slate-600">{asset.siteId}</div>
                </td>
                <td className="px-6 py-4">
                  <div className="flex items-center gap-1.5 text-slate-600">
                    <Globe className="h-3.5 w-3.5 text-slate-400" />
                    {asset.country}
                  </div>
                </td>
                <td className="px-6 py-4">
                  <div className="relative group/status min-w-[120px]">
                    {updatingAssetId === asset.id ? (
                      <div className="flex items-center gap-2 text-blue-600 text-xs font-semibold">
                        <Loader2 className="h-3 w-3 animate-spin" /> Updating...
                      </div>
                    ) : (
                      <select 
                        value={asset.status}
                        onChange={(e) => handleStatusChange(asset, e.target.value as AssetStatus)}
                        className={`px-3 py-1 rounded-full text-xs font-bold border transition-all appearance-none outline-none cursor-pointer ${getStatusColor(asset.status)}`}
                      >
                        {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
                      </select>
                    )}
                  </div>
                </td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button 
                      onClick={() => setViewingHistory(asset)}
                      className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                      title="View History"
                    >
                      <HistoryIcon className="h-4 w-4" />
                    </button>
                    <button 
                      onClick={() => setAssetsToDelete([asset])}
                      className="p-2 text-slate-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-all"
                      title="Delete Asset"
                    >
                      <Trash2 className="h-4 w-4" />
                    </button>
                  </div>
                </td>
              </tr>
            ))}
            {currentItems.length === 0 && (
              <tr>
                <td colSpan={7} className="px-6 py-12 text-center text-slate-400 font-medium">
                  {totalItems > 0 ? "Adjust pagination or filters to see more results." : "No assets found matching your criteria."}
                </td>
              </tr>
            )}
          </tbody>
        </table>

        {/* Pagination Footer */}
        {totalItems > 0 && (
          <div className="bg-slate-50 border-t border-slate-100 px-6 py-4 flex flex-col sm:flex-row items-center justify-between gap-4">
            <div className="text-xs font-medium text-slate-500">
              Showing <span className="text-slate-900 font-bold">{startIndex + 1}</span> to <span className="text-slate-900 font-bold">{endIndex}</span> of <span className="text-slate-900 font-bold">{totalItems}</span> assets
            </div>

            <div className="flex items-center gap-1">
              <button 
                onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                disabled={currentPage === 1}
                className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronLeft className="h-4 w-4" />
              </button>

              <div className="flex items-center gap-1 px-2">
                {Array.from({ length: Math.min(5, totalPages) }, (_, i) => {
                  let pageNum = i + 1;
                  // Basic slider for many pages
                  if (totalPages > 5 && currentPage > 3) {
                    pageNum = currentPage - 3 + i + 1;
                    if (pageNum > totalPages) pageNum = totalPages - (4 - i);
                  }

                  return (
                    <button
                      key={pageNum}
                      onClick={() => setCurrentPage(pageNum)}
                      className={`min-w-[32px] h-8 text-xs font-bold rounded-lg transition-all ${
                        currentPage === pageNum 
                          ? 'bg-blue-600 text-white shadow-md shadow-blue-600/20' 
                          : 'text-slate-600 hover:bg-white hover:border-slate-300 border border-transparent'
                      }`}
                    >
                      {pageNum}
                    </button>
                  );
                })}
              </div>

              <button 
                onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                disabled={currentPage === totalPages}
                className="p-2 rounded-lg border border-slate-200 bg-white text-slate-600 hover:bg-slate-50 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                <ChevronRight className="h-4 w-4" />
              </button>
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

export interface HistoryEntry {
  timestamp: number;
  field: string;
  oldValue: any;
  newValue: any;
}

export interface Asset {
  serialNumber: string; // Primary Key
  model: string;
  siteID: string;
  country: string;
  status: AssetStatus;
  comments?: string;
  createdAt: number;
  history?: HistoryEntry[];
}

export enum AssetStatus {
  Normal = 'Normal',
  RMARequested = 'RMA Requested',
  RMAShipped = 'RMA Shipped',
  RMAEligible = 'RMA Eligible',
  RMANotEligible = 'RMA Not Eligible',
  Deprecated = 'Deprecated',
  Unknown = 'Unknown'
}

export interface ParseResult {
  assets: Omit<Asset, 'createdAt'>[];
}

import { DynamoDBClient } from "@aws-sdk/client-dynamodb";
import { 
  DynamoDBDocumentClient, 
  ScanCommand, 
  PutCommand, 
  BatchWriteCommand
} from "@aws-sdk/lib-dynamodb";
import { Asset, AssetStatus, HistoryEntry } from '../types';

const getEnv = (key: string): string | undefined => {
  return (import.meta as any).env?.[key];
};

const REGION = getEnv('VITE_ASSET_AWS_REGION') || 'us-east-1';
const TABLE_NAME = getEnv('VITE_ASSET_DYNAMO_TABLE') || 'Assets';
const ACCESS_KEY = getEnv('VITE_ASSET_ACCESS_KEY');
const SECRET_KEY = getEnv('VITE_ASSET_SECRET_KEY');

let docClient: DynamoDBDocumentClient | null = null;

const getDocClient = () => {
  if (!docClient) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      throw new Error("AWS Credentials missing. Check environment variables.");
    }
    const client = new DynamoDBClient({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
    docClient = DynamoDBDocumentClient.from(client, {
      marshallOptions: {
        removeUndefinedValues: true,
        convertEmptyValues: true
      }
    });
  }
  return docClient;
};

export const fetchAssets = async (): Promise<Asset[]> => {
  try {
    const client = getDocClient();
    const command = new ScanCommand({ TableName: TABLE_NAME });
    const response = await client.send(command);
    return (response.Items || []).map((item: any) => ({
      ...item,
      status: item.status || AssetStatus.Normal,
      history: item.history || []
    })) as Asset[];
  } catch (e: any) {
    console.error('Fetch Error:', e);
    throw e;
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  try {
    const client = getDocClient();
    const batches: Asset[][] = [];
    for (let i = 0; i < newAssets.length; i += 25) {
      batches.push(newAssets.slice(i, i + 25));
    }

    const writePromises = batches.map(async (batch) => {
      const putRequests = batch.map(asset => ({
        PutRequest: {
          Item: {
            ...asset,
            history: asset.history || [{
              timestamp: Date.now(),
              field: 'System',
              oldValue: null,
              newValue: 'Initial Asset Registration'
            }]
          }
        }
      }));

      const command = new BatchWriteCommand({
        RequestItems: { [TABLE_NAME]: putRequests }
      });
      return client.send(command);
    });

    await Promise.all(writePromises);
  } catch (e: any) {
    console.error('Bulk Upload Error:', e);
    if (e.message.includes('key element')) {
      throw new Error(`Schema Error: Ensure your DynamoDB Table "${TABLE_NAME}" has a Partition Key named exactly "serialNumber" (case-sensitive).`);
    }
    throw e;
  }
};

export const updateAsset = async (serialNumber: string, updates: Partial<Asset>): Promise<void> => {
  try {
    const client = getDocClient();
    const currentAssets = await fetchAssets(); 
    const asset = currentAssets.find(a => a.serialNumber === serialNumber);

    if (!asset) throw new Error("Asset not found.");

    const newHistory: HistoryEntry[] = [...(asset.history || [])];
    Object.entries(updates).forEach(([key, value]) => {
      const field = key as keyof Asset;
      if (asset[field] !== value && !['history', 'serialNumber', 'createdAt'].includes(key)) {
        newHistory.push({
          timestamp: Date.now(),
          field: key,
          oldValue: asset[field],
          newValue: value
        });
      }
    });

    const updatedAsset = { ...asset, ...updates, history: newHistory };
    await client.send(new PutCommand({
      TableName: TABLE_NAME,
      Item: updatedAsset
    }));
  } catch (e: any) {
    console.error('Update Error:', e);
    throw e;
  }
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  try {
    const client = getDocClient();
    const batches: Asset[][] = [];
    for (let i = 0; i < assetsToDelete.length; i += 25) {
      batches.push(assetsToDelete.slice(i, i + 25));
    }

    const deletePromises = batches.map(async (batch) => {
      const deleteRequests = batch.map(asset => ({
        DeleteRequest: {
          Key: { serialNumber: asset.serialNumber }
        }
      }));
      const command = new BatchWriteCommand({
        RequestItems: { [TABLE_NAME]: deleteRequests }
      });
      return client.send(command);
    });

    await Promise.all(deletePromises);
  } catch (e: any) {
    console.error('Delete Error:', e);
    throw e;
  }
};

import { useState, useRef } from 'react';
import { Asset, AssetStatus } from '../types';
import { parseAssetsFromText } from '../services/geminiService';
import { Bot, Save, AlertCircle, CheckCircle, Upload, FileSpreadsheet, Download, X } from 'lucide-react';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetFormProps {
  onAddAssets: (assets: Asset[]) => void;
  onCancel: () => void;
}

export const AssetForm: React.FC<AssetFormProps> = ({ onAddAssets, onCancel }) => {
  const [mode, setMode] = useState<'manual' | 'ai' | 'bulk'>('manual');
  const [manualForm, setManualForm] = useState({
    model: '',
    serialNumber: '',
    siteID: '',
    country: '',
    comments: '',
    status: AssetStatus.Normal
  });

  const [aiInput, setAiInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bulkPreview, setBulkPreview] = useState<Asset[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualForm.model || !manualForm.serialNumber || !manualForm.siteID) {
      setError("Please fill in required fields (Model, Serial, SiteID).");
      return;
    }
    onAddAssets([{ ...manualForm, createdAt: Date.now() }]);
  };

  const handleAiParse = async () => {
    if (!aiInput.trim()) return;
    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parseAssetsFromText(aiInput);
      if (parsedData.length === 0) {
        setError("No assets found in text.");
      } else {
        const newAssets: Asset[] = parsedData.map(p => ({
          serialNumber: p.serialNumber || 'UNKNOWN-' + Date.now(),
          model: p.model || 'Unknown',
          siteID: (p as any).siteID || (p as any).siteId || 'Unknown',
          country: p.country || '',
          comments: (p as any).comments || '',
          status: (p.status as AssetStatus) || AssetStatus.Normal,
          createdAt: Date.now()
        }));
        onAddAssets(newAssets);
      }
    } catch (err) {
      setError("AI Processing failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const processRowToAsset = (row: any): Asset | null => {
    const normalized: Record<string, any> = {};
    Object.keys(row).forEach(k => normalized[k.toLowerCase().trim().replace(/[^a-z0-9]/g, '')] = row[k]);

    const model = normalized['model'] || normalized['assetmodel'] || normalized['product'];
    const serial = normalized['serialnumber'] || normalized['serial'] || normalized['sn'];
    const site = normalized['siteid'] || normalized['site'];
    const country = normalized['country'] || normalized['region'];
    const comments = normalized['comments'] || normalized['rmastatus'] || normalized['notes'];

    if (model && serial && site) {
      return {
        serialNumber: String(serial).trim(),
        model: String(model).trim(),
        siteID: String(site).trim(),
        country: country ? String(country).trim() : '',
        comments: comments ? String(comments).trim() : '',
        status: AssetStatus.Normal,
        createdAt: Date.now()
      };
    }
    return null;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = file.name.endsWith('.csv') 
          ? Papa.parse(evt.target?.result as string, { header: true }).data
          : XLSX.utils.sheet_to_json(XLSX.read(evt.target?.result, { type: 'binary' }).Sheets[XLSX.read(evt.target?.result, { type: 'binary' }).SheetNames[0]]);

        const assets = data.map(processRowToAsset).filter((a): a is Asset => a !== null);
        if (assets.length === 0) setError("No valid assets found. Headers must include Model, Serial Number, and SiteID.");
        else setBulkPreview(assets);
      } catch (err) { setError("File parsing failed."); }
    };
    file.name.endsWith('.csv') ? reader.readAsText(file) : reader.readAsBinaryString(file);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex gap-2 p-1 bg-slate-100 rounded-lg justify-center">
        {['manual', 'bulk', 'ai'].map((m) => (
          <button key={m} onClick={() => setMode(m as any)} className={`px-4 py-2 rounded-md text-sm font-medium capitalize ${mode === m ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-600'}`}>
            {m} entry
          </button>
        ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8">
        {error && <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2 text-sm border border-red-100"><AlertCircle className="h-5 w-5" />{error}</div>}

        {mode === 'manual' && (
          <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <input type="text" required className="w-full px-4 py-2 border rounded-lg" placeholder="Asset Model *" value={manualForm.model} onChange={e => setManualForm({...manualForm, model: e.target.value})} />
              <input type="text" required className="w-full px-4 py-2 border rounded-lg" placeholder="Serial Number *" value={manualForm.serialNumber} onChange={e => setManualForm({...manualForm, serialNumber: e.target.value})} />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <input type="text" required className="w-full px-4 py-2 border rounded-lg" placeholder="SiteID *" value={manualForm.siteID} onChange={e => setManualForm({...manualForm, siteID: e.target.value})} />
              <input type="text" className="w-full px-4 py-2 border rounded-lg" placeholder="Country" value={manualForm.country} onChange={e => setManualForm({...manualForm, country: e.target.value})} />
              <select className="w-full px-4 py-2 border rounded-lg" value={manualForm.status} onChange={e => setManualForm({...manualForm, status: e.target.value as AssetStatus})}>
                {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
              </select>
            </div>
            <textarea className="w-full px-4 py-2 border rounded-lg" placeholder="Comments / RMA Info" value={manualForm.comments} onChange={e => setManualForm({...manualForm, comments: e.target.value})} />
            <div className="flex gap-4"><button type="submit" className="flex-1 bg-blue-600 text-white py-3 rounded-lg font-bold flex items-center justify-center gap-2"><Save className="h-5 w-5" />Save</button><button type="button" onClick={onCancel} className="px-6 py-3 border rounded-lg">Cancel</button></div>
          </form>
        )}

        {mode === 'bulk' && (
          <div className="space-y-6 text-center">
            {bulkPreview.length === 0 ? (
              <>
                <div className="border-2 border-dashed border-slate-300 rounded-xl p-12 hover:bg-slate-50 transition-colors cursor-pointer" onClick={() => fileInputRef.current?.click()}>
                  <input type="file" accept=".csv,.xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
                  <Upload className="h-12 w-12 text-blue-600 mx-auto mb-4" />
                  <h3 className="text-lg font-bold">Upload Excel or CSV</h3>
                  <p className="text-slate-500 text-sm">Required columns: Model, Serial Number, SiteID</p>
                </div>
                <button onClick={onCancel} className="text-slate-500 font-bold">Back</button>
              </>
            ) : (
              <div className="space-y-4">
                <div className="max-h-60 overflow-y-auto border rounded-lg"><table className="w-full text-xs text-left"><thead className="bg-slate-50"><tr><th className="p-2">Model</th><th className="p-2">Serial</th><th className="p-2">SiteID</th></tr></thead><tbody>{bulkPreview.map((a, i) => <tr key={i}><td className="p-2">{a.model}</td><td className="p-2">{a.serialNumber}</td><td className="p-2">{a.siteID}</td></tr>)}</tbody></table></div>
                <div className="flex gap-4"><button onClick={() => onAddAssets(bulkPreview)} className="flex-1 bg-emerald-600 text-white py-3 rounded-lg font-bold">Import {bulkPreview.length} Assets</button><button onClick={() => setBulkPreview([])} className="px-6 py-3 border rounded-lg">Reset</button></div>
              </div>
            )}
          </div>
        )}

        {mode === 'ai' && (
          <div className="space-y-6">
            <textarea className="w-full px-4 py-3 border rounded-lg h-48 font-mono text-sm" value={aiInput} onChange={e => setAiInput(e.target.value)} placeholder="Paste asset details here..." />
            <div className="flex gap-4"><button onClick={handleAiParse} disabled={isProcessing || !aiInput.trim()} className="flex-1 bg-purple-600 text-white py-3 rounded-lg font-bold disabled:opacity-50">{isProcessing ? "Processing..." : "AI Extract & Save"}</button><button onClick={onCancel} className="px-6 py-3 border rounded-lg">Cancel</button></div>
          </div>
        )}
      </div>
    </div>
  );
};

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Asset, AssetStatus } from '../types';
import { Search, Sparkles, Trash2, Loader2, Globe, Edit3, AlertTriangle, X, History as HistoryIcon, ArrowRight, Hash, ChevronLeft, ChevronRight, MessageSquare } from 'lucide-react';
import { generateAssetReport } from '../services/geminiService';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateAsset: (serialNumber: string, updates: Partial<Asset>) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateAsset }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedSerials, setSelectedSerials] = useState<Set<string>>(new Set());
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [itemsPerPage, setItemsPerPage] = useState<number>(25);
  const [currentPage, setCurrentPage] = useState<number>(1);
  const [editing, setEditing] = useState<{ serial: string, field: keyof Asset, value: string } | null>(null);
  const editInputRef = useRef<HTMLInputElement>(null);
  const [assetsToDelete, setAssetsToDelete] = useState<Asset[] | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Asset | null>(null);

  useEffect(() => { if (editing && editInputRef.current) { editInputRef.current.focus(); editInputRef.current.select(); } }, [editing]);
  useEffect(() => { setCurrentPage(1); }, [searchTerm, statusFilter, itemsPerPage]);

  const filtered = useMemo(() => assets.filter(a => {
    const term = searchTerm.toLowerCase();
    const matchesSearch = a.model.toLowerCase().includes(term) || a.serialNumber.toLowerCase().includes(term) || a.siteID.toLowerCase().includes(term) || (a.comments || '').toLowerCase().includes(term);
    return matchesSearch && (statusFilter === 'All' || a.status === statusFilter);
  }), [assets, searchTerm, statusFilter]);

  const currentItems = filtered.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);
  const allSelected = currentItems.length > 0 && currentItems.every(a => selectedSerials.has(a.serialNumber));

  const toggleSelect = (s: string) => {
    const next = new Set(selectedSerials);
    next.has(s) ? next.delete(s) : next.add(s);
    setSelectedSerials(next);
  };

  const saveEdit = async () => {
    if (!editing) return;
    const asset = assets.find(a => a.serialNumber === editing.serial);
    if (!asset || asset[editing.field] === editing.value) { setEditing(null); return; }
    setUpdatingId(asset.serialNumber);
    const updates = { [editing.field]: editing.value };
    setEditing(null);
    try { await onUpdateAsset(asset.serialNumber, updates); } finally { setUpdatingId(null); }
  };

  return (
    <div className="space-y-6">
      {assetsToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-6 max-w-md w-full">
            <h3 className="text-xl font-bold text-red-600 mb-4 flex items-center gap-2"><AlertTriangle /> Delete Assets?</h3>
            <p className="text-sm text-slate-600 mb-6">Permanently remove {assetsToDelete.length} assets from DynamoDB?</p>
            <div className="flex gap-3"><button onClick={() => setAssetsToDelete(null)} className="flex-1 py-2 border rounded-xl">Cancel</button><button onClick={() => { onDelete(assetsToDelete.map(a => a.serialNumber)); setAssetsToDelete(null); setSelectedSerials(new Set()); }} className="flex-1 py-2 bg-red-600 text-white rounded-xl font-bold">Delete</button></div>
          </div>
        </div>
      )}

      {viewingHistory && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-6 max-w-2xl w-full max-h-[80vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold flex items-center gap-2 text-blue-600"><HistoryIcon /> History: {viewingHistory.serialNumber}</h3>
              <button onClick={() => setViewingHistory(null)}><X /></button>
            </div>
            <div className="space-y-4">{(viewingHistory.history || []).slice().reverse().map((h, i) => <div key={i} className="p-3 border rounded-lg bg-slate-50"><div className="text-[10px] font-bold text-slate-400 uppercase mb-1">{h.field} - {new Date(h.timestamp).toLocaleString()}</div><div className="text-sm font-semibold">{h.oldValue !== null && <span className="line-through text-slate-300 mr-2">{h.oldValue}</span>}{h.newValue}</div></div>)}</div>
          </div>
        </div>
      )}

      <div className="bg-white p-4 rounded-xl border flex flex-col md:flex-row gap-4 items-center justify-between shadow-sm">
        <div className="flex gap-4 w-full md:w-auto">
          <div className="relative flex-1 md:w-80"><Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" /><input type="text" placeholder="Search inventory..." className="w-full pl-10 pr-4 py-2 border rounded-lg text-sm" value={searchTerm} onChange={e => setSearchTerm(e.target.value)} /></div>
        </div>
        <div className="flex gap-3 w-full md:w-auto">
          <select className="px-3 py-2 border rounded-lg text-sm" value={statusFilter} onChange={e => setStatusFilter(e.target.value)}><option value="All">All Statuses</option>{Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}</select>
          <button onClick={async () => { setIsAnalyzing(true); try { setAnalysis(await generateAssetReport(filtered)); } finally { setIsAnalyzing(false); } }} className="flex items-center gap-2 px-4 py-2 bg-indigo-600 text-white rounded-lg text-sm font-bold">{isAnalyzing ? <Loader2 className="animate-spin h-4 w-4" /> : <Sparkles className="h-4 w-4" />} AI Analysis</button>
        </div>
      </div>

      {analysis && <div className="p-6 bg-indigo-50 rounded-xl border border-indigo-100 relative"><button onClick={() => setAnalysis(null)} className="absolute top-4 right-4 text-slate-400"><X /></button><div className="prose prose-sm text-slate-700">{analysis.split('\n').map((l, i) => <p key={i}>{l}</p>)}</div></div>}

      <div className="bg-white rounded-xl border shadow-sm overflow-hidden overflow-x-auto">
        <table className="w-full text-sm text-left">
          <thead className="bg-slate-50 border-b text-[10px] font-bold uppercase text-slate-500 tracking-wider">
            <tr>
              <th className="px-6 py-4 w-10 text-center"><input type="checkbox" checked={allSelected} onChange={(e) => { const next = new Set(selectedSerials); currentItems.forEach(a => e.target.checked ? next.add(a.serialNumber) : next.delete(a.serialNumber)); setSelectedSerials(next); }} /></th>
              <th className="px-6 py-4">Model</th>
              <th className="px-6 py-4">Serial Number (PK)</th>
              <th className="px-6 py-4">SiteID</th>
              <th className="px-6 py-4">Country</th>
              <th className="px-6 py-4">Status</th>
              <th className="px-6 py-4">Comments</th>
              <th className="px-6 py-4 text-right">Actions</th>
            </tr>
          </thead>
          <tbody className="divide-y">
            {currentItems.map(a => (
              <tr key={a.serialNumber} className={`hover:bg-slate-50/50 ${selectedSerials.has(a.serialNumber) ? 'bg-blue-50/30' : ''}`}>
                <td className="px-6 py-4 text-center"><input type="checkbox" checked={selectedSerials.has(a.serialNumber)} onChange={() => toggleSelect(a.serialNumber)} /></td>
                <td className="px-6 py-4 font-bold">{a.model}</td>
                <td className="px-6 py-4 font-mono text-xs text-blue-600 font-bold">{a.serialNumber}</td>
                <td className="px-6 py-4 font-semibold">{a.siteID}</td>
                <td className="px-6 py-4 text-slate-500"><Globe className="inline h-3 w-3 mr-1" />{a.country}</td>
                <td className="px-6 py-4">
                  {updatingId === a.serialNumber ? <Loader2 className="h-4 w-4 animate-spin text-blue-600" /> : (
                    <select value={a.status} onChange={(e) => onUpdateAsset(a.serialNumber, { status: e.target.value as AssetStatus })} className="px-2 py-1 border rounded-full text-[10px] font-bold uppercase tracking-wider">{Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}</select>
                  )}
                </td>
                <td className="px-6 py-4 text-slate-500 italic max-w-xs truncate">{a.comments || '-'}</td>
                <td className="px-6 py-4 text-right">
                  <div className="flex justify-end gap-2">
                    <button onClick={() => setViewingHistory(a)} className="p-2 hover:text-blue-600" title="History"><HistoryIcon className="h-4 w-4" /></button>
                    <button onClick={() => setAssetsToDelete([a])} className="p-2 hover:text-red-600" title="Delete"><Trash2 className="h-4 w-4" /></button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        {filtered.length === 0 && <div className="p-12 text-center text-slate-400 font-bold">No assets found in DynamoDB.</div>}
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AssetList } from './components/AssetList';
import { AssetForm } from './components/AssetForm';
import { Login } from './components/Login';
import { Asset } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAsset } from './services/storageService';
import { Loader2, DatabaseZap, ShieldCheck, PlusCircle, AlertCircle } from 'lucide-react';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('portal_auth') === 'true');
  const [view, setView] = useState<'list' | 'add'>('list');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => { if (isAuthenticated) loadData(); }, [isAuthenticated]);

  const loadData = async () => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
    } catch (error: any) {
      setIsConnected(false);
      showNotification(error.message || 'DynamoDB Connection failed.', 'error');
    } finally { setIsLoading(false); }
  };

  const handleLogin = async (user: string, pass: string): Promise<boolean> => {
    if (user === 'admin' && pass === 'password123') {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error: any) { showNotification(error.message, 'error'); } 
    finally { setIsSaving(false); }
  };

  const handleUpdateAsset = async (serialNumber: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(serialNumber, updates);
      setAssets(prev => prev.map(a => a.serialNumber === serialNumber ? { ...a, ...updates } : a));
    } catch (error: any) { showNotification(error.message, 'error'); }
  };

  const handleDeleteAssets = async (serials: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => serials.includes(a.serialNumber));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !serials.includes(a.serialNumber)));
      showNotification('Assets removed', 'success');
    } catch (error: any) { showNotification(error.message, 'error'); }
    finally { setIsSaving(false); }
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;
  if (isLoading && assets.length === 0) return <div className="min-h-screen flex items-center justify-center font-bold text-slate-400">Loading Cloud Inventory...</div>;

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header currentView={view} onNavigate={setView} onLogout={() => { setIsAuthenticated(false); sessionStorage.removeItem('portal_auth'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        <div className="mb-4 flex justify-end">
          <div className={`px-3 py-1 rounded-full text-[10px] font-bold border flex items-center gap-2 ${isConnected ? 'bg-blue-50 text-blue-700' : 'bg-red-50 text-red-700'}`}>
            <DatabaseZap className="h-3 w-3" /> {isConnected ? 'DynamoDB Linked' : 'Disconnected'}
          </div>
        </div>
        {notification && <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-xl shadow-xl z-50 border bg-white ${notification.type === 'success' ? 'text-emerald-700' : 'text-red-700'}`}>{notification.message}</div>}
        {isSaving && <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[200] flex items-center justify-center font-bold">Syncing with AWS...</div>}

        {view === 'list' ? (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <h2 className="text-3xl font-extrabold">Inventory</h2>
              <button onClick={() => setView('add')} className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2"><PlusCircle className="h-4 w-4" /> Add Asset</button>
            </div>
            <AssetList assets={assets} onDelete={handleDeleteAssets} onUpdateAsset={handleUpdateAsset} />
          </div>
        ) : <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />}
      </main>
    </div>
  );
}

export default App;

import { GoogleGenAI, Type } from "@google/genai";
import { Asset } from "../types";

// Parse unstructured text into structured asset data
export const parseAssetsFromText = async (text: string): Promise<Partial<Asset>[]> => {
  // Always initialize with the specific API key from environment
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `Extract asset information from the following text. 
      The text may contain multiple assets. 
      Extract or infer the Country (e.g., "Germany", "UK", "USA") for each asset.
      Infer the Status from the context if possible.
      Valid statuses are: "Normal", "RMA Requested", "RMA Shipped", "RMA Eligible", "RMA Not Eligible", "Deprecated", "Unknown".
      If no specific status context is found, default to "Normal".

      Text to process:
      "${text}"`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              model: { type: Type.STRING, description: "The model name or number of the asset" },
              serialNumber: { type: Type.STRING, description: "The serial number" },
              // Fix: Use siteID instead of siteId to align with Asset interface
              siteID: { type: Type.STRING, description: "The location or Site ID" },
              country: { type: Type.STRING, description: "The country where the asset is located" },
              status: { 
                type: Type.STRING, 
                description: "The status of the asset. Must be one of: Normal, RMA Requested, RMA Shipped, RMA Eligible, RMA Not Eligible, Deprecated, Unknown" 
              }
            },
            // Fix: Updated required property list to use siteID
            required: ["model", "serialNumber", "siteID", "country", "status"],
            // propertyOrdering is recommended for structured JSON output
            // Fix: Updated propertyOrdering to use siteID
            propertyOrdering: ["model", "serialNumber", "siteID", "country", "status"]
          }
        }
      }
    });

    // Directly access the .text property as per Gemini API guidelines
    if (response.text) {
      return JSON.parse(response.text.trim()) as Partial<Asset>[];
    }
    return [];
  } catch (error) {
    console.error("Gemini parse error:", error);
    throw new Error("Failed to parse asset data using AI.");
  }
};

// Generate a summary report of the assets
export const generateAssetReport = async (assets: Asset[]): Promise<string> => {
  if (assets.length === 0) return "No assets to analyze.";

  // Always initialize with the specific API key from environment
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  try {
    const dataStr = JSON.stringify(assets.map(a => ({
      model: a.model,
      // Fix: Property access should be siteID as per Asset type definition
      site: a.siteID,
      country: a.country,
      status: a.status
    })));

    const response = await ai.models.generateContent({
      model: "gemini-3-pro-preview",
      contents: `Analyze this asset dataset and provide a brief executive summary suitable for a dashboard.
      Focus on:
      1. Total count and breakdown by Country and Site ID.
      2. Identify any patterns in Status/RMA geographically or by model.
      3. Actionable recommendations.

      Keep it concise (max 200 words). Use Markdown for formatting.

      Dataset:
      ${dataStr}`
    });

    // Directly access the .text property as per Gemini API guidelines
    return response.text || "Analysis failed to generate text.";
  } catch (error) {
    console.error("Gemini analysis error:", error);
    return "Could not generate AI report at this time.";
  }
};

