import { DynamoDBClient } from "@aws-sdk/client-dynamodb";
import { 
  DynamoDBDocumentClient, 
  ScanCommand, 
  PutCommand, 
  DeleteCommand,
  BatchWriteCommand
} from "@aws-sdk/lib-dynamodb";
import { Asset, AssetStatus, HistoryEntry } from '../types';

const getEnv = (key: string): string | undefined => {
  return (import.meta as any).env?.[key];
};

const REGION = getEnv('VITE_ASSET_AWS_REGION') || 'us-east-1';
const TABLE_NAME = getEnv('VITE_ASSET_DYNAMO_TABLE') || 'Assets';
const ACCESS_KEY = getEnv('VITE_ASSET_ACCESS_KEY');
const SECRET_KEY = getEnv('VITE_ASSET_SECRET_KEY');

let docClient: DynamoDBDocumentClient | null = null;

const getDocClient = () => {
  if (!docClient) {
    if (!ACCESS_KEY || !SECRET_KEY) {
      throw new Error("AWS Credentials missing. Check environment variables.");
    }
    const client = new DynamoDBClient({
      region: REGION,
      credentials: {
        accessKeyId: ACCESS_KEY,
        secretAccessKey: SECRET_KEY,
      },
    });
    docClient = DynamoDBDocumentClient.from(client, {
      marshallOptions: {
        removeUndefinedValues: true,
        convertEmptyValues: true
      }
    });
  }
  return docClient;
};

export const fetchAssets = async (): Promise<Asset[]> => {
  try {
    const client = getDocClient();
    const command = new ScanCommand({ TableName: TABLE_NAME });
    const response = await client.send(command);
    return (response.Items || []).map((item: any) => ({
      ...item,
      status: item.status || AssetStatus.Normal,
      history: item.history || []
    })) as Asset[];
  } catch (e: any) {
    console.error('Fetch Error:', e);
    throw e;
  }
};

export const addAssets = async (newAssets: Asset[]): Promise<void> => {
  try {
    const client = getDocClient();
    const batches: Asset[][] = [];
    for (let i = 0; i < newAssets.length; i += 25) {
      batches.push(newAssets.slice(i, i + 25));
    }

    const writePromises = batches.map(async (batch) => {
      const putRequests = batch.map(asset => ({
        PutRequest: {
          Item: {
            ...asset,
            history: asset.history || [{
              timestamp: Date.now(),
              field: 'System',
              oldValue: null,
              newValue: 'Initial Asset Registration'
            }]
          }
        }
      }));

      const command = new BatchWriteCommand({
        RequestItems: { [TABLE_NAME]: putRequests }
      });
      return client.send(command);
    });

    await Promise.all(writePromises);
  } catch (e: any) {
    console.error('Bulk Upload Error:', e);
    if (e.message.includes('key element')) {
      throw new Error(`Schema Error: Ensure your DynamoDB Table "${TABLE_NAME}" has a Partition Key named exactly "serialNumber" (case-sensitive).`);
    }
    throw e;
  }
};

export const updateAsset = async (serialNumber: string, updates: Partial<Asset>): Promise<void> => {
  try {
    const client = getDocClient();
    const currentAssets = await fetchAssets(); 
    const asset = currentAssets.find(a => a.serialNumber === serialNumber);

    if (!asset) throw new Error("Asset not found.");

    const newHistory: HistoryEntry[] = [...(asset.history || [])];
    Object.entries(updates).forEach(([key, value]) => {
      const field = key as keyof Asset;
      if (asset[field] !== value && !['history', 'createdAt'].includes(key)) {
        newHistory.push({
          timestamp: Date.now(),
          field: key,
          oldValue: asset[field],
          newValue: value
        });
      }
    });

    const updatedAsset = { ...asset, ...updates, history: newHistory };

    // If PK (serialNumber) changed, we need to delete the old record and create the new one
    if (updates.serialNumber && updates.serialNumber !== serialNumber) {
      await client.send(new DeleteCommand({
        TableName: TABLE_NAME,
        Key: { serialNumber }
      }));
    }

    await client.send(new PutCommand({
      TableName: TABLE_NAME,
      Item: updatedAsset
    }));
  } catch (e: any) {
    console.error('Update Error:', e);
    throw e;
  }
};

export const deleteAssets = async (assetsToDelete: Asset[]): Promise<void> => {
  try {
    const client = getDocClient();
    const batches: Asset[][] = [];
    for (let i = 0; i < assetsToDelete.length; i += 25) {
      batches.push(assetsToDelete.slice(i, i + 25));
    }

    const deletePromises = batches.map(async (batch) => {
      const deleteRequests = batch.map(asset => ({
        DeleteRequest: {
          Key: { serialNumber: asset.serialNumber }
        }
      }));
      const command = new BatchWriteCommand({
        RequestItems: { [TABLE_NAME]: deleteRequests }
      });
      return client.send(command);
    });

    await Promise.all(deletePromises);
  } catch (e: any) {
    console.error('Delete Error:', e);
    throw e;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { Asset, AssetStatus } from '../types';
import { 
  Search, 
  Sparkles, 
  Trash2, 
  Loader2, 
  Globe, 
  AlertTriangle, 
  X, 
  History as HistoryIcon,
  ChevronLeft,
  ChevronRight,
  Rows,
  FileDown,
  FileText,
  Table as TableIcon,
  Pencil,
  Check,
  XCircle
} from 'lucide-react';
import { generateAssetReport } from '../services/geminiService';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateAsset: (serialNumber: string, updates: Partial<Asset>) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateAsset }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [selectedSerials, setSelectedSerials] = useState<Set<string>>(new Set());
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Inline Edit State
  const [editingSerial, setEditingSerial] = useState<string | null>(null);
  const [editData, setEditData] = useState<Partial<Asset>>({});

  // Pagination State
  const [itemsPerPage, setItemsPerPage] = useState<number>(50);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [assetsToDelete, setAssetsToDelete] = useState<Asset[] | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Asset | null>(null);

  // Helper for status colors
  const getStatusClasses = (status: AssetStatus) => {
    switch (status) {
      case AssetStatus.Normal: 
        return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case AssetStatus.RMARequested: 
        return 'bg-amber-50 text-amber-700 border-amber-200';
      case AssetStatus.RMAShipped: 
        return 'bg-blue-50 text-blue-700 border-blue-200';
      case AssetStatus.RMAEligible: 
        return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case AssetStatus.RMANotEligible: 
        return 'bg-rose-50 text-rose-700 border-rose-200';
      case AssetStatus.Deprecated: 
        return 'bg-slate-100 text-slate-600 border-slate-200';
      default: 
        return 'bg-slate-50 text-slate-500 border-slate-200';
    }
  };

  // Reset page on search or filter change
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter, itemsPerPage]);

  const filtered = useMemo(() => assets.filter(a => {
    const term = searchTerm.toLowerCase();
    const matchesSearch = 
      a.model.toLowerCase().includes(term) || 
      a.serialNumber.toLowerCase().includes(term) || 
      a.siteID.toLowerCase().includes(term) || 
      (a.comments || '').toLowerCase().includes(term);
    return matchesSearch && (statusFilter === 'All' || a.status === statusFilter);
  }), [assets, searchTerm, statusFilter]);

  const totalPages = Math.ceil(filtered.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const currentItems = filtered.slice(startIndex, startIndex + itemsPerPage);
  const allSelected = currentItems.length > 0 && currentItems.every(a => selectedSerials.has(a.serialNumber));

  const toggleSelect = (s: string) => {
    const next = new Set(selectedSerials);
    next.has(s) ? next.delete(s) : next.add(s);
    setSelectedSerials(next);
  };

  const handlePageChange = (newPage: number) => {
    if (newPage >= 1 && newPage <= totalPages) {
      setCurrentPage(newPage);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startEditing = (asset: Asset) => {
    setEditingSerial(asset.serialNumber);
    setEditData({
      model: asset.model,
      serialNumber: asset.serialNumber,
      siteID: asset.siteID,
      country: asset.country
    });
  };

  const cancelEditing = () => {
    setEditingSerial(null);
    setEditData({});
  };

  const handleSaveEdit = async () => {
    if (!editingSerial) return;
    setUpdatingId(editingSerial);
    try {
      await onUpdateAsset(editingSerial, editData);
      setEditingSerial(null);
      setEditData({});
    } finally {
      setUpdatingId(null);
    }
  };

  const prepareExportData = () => {
    return filtered.map(a => ({
      'Model': a.model,
      'Serial Number': a.serialNumber,
      'Site ID': a.siteID,
      'Country': a.country,
      'Status': a.status,
      'Comments': a.comments || '',
      'Created At': new Date(a.createdAt).toLocaleString(),
      'History Events': (a.history || []).length
    }));
  };

  const exportCSV = () => {
    const data = prepareExportData();
    const csv = Papa.unparse(data);
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `AssetTrack_Export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  const exportExcel = () => {
    const data = prepareExportData();
    const worksheet = XLSX.utils.json_to_sheet(data);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Assets");
    XLSX.writeFile(workbook, `AssetTrack_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
    setShowExportMenu(false);
  };

  return (
    <div className="space-y-6">
      {assetsToDelete && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-6 max-w-md w-full">
            <h3 className="text-xl font-bold text-red-600 mb-4 flex items-center gap-2"><AlertTriangle /> Delete Assets?</h3>
            <p className="text-sm text-slate-600 mb-6">Permanently remove {assetsToDelete.length} assets from DynamoDB?</p>
            <div className="flex gap-3">
              <button onClick={() => setAssetsToDelete(null)} className="flex-1 py-2 border rounded-xl">Cancel</button>
              <button 
                onClick={() => { 
                  onDelete(assetsToDelete.map(a => a.serialNumber)); 
                  setAssetsToDelete(null); 
                  setSelectedSerials(new Set()); 
                }} 
                className="flex-1 py-2 bg-red-600 text-white rounded-xl font-bold"
              >
                Delete
              </button>
            </div>
          </div>
        </div>
      )}

      {viewingHistory && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-2xl p-6 max-w-2xl w-full max-h-[80vh] overflow-y-auto">
            <div className="flex justify-between items-center mb-6">
              <h3 className="font-bold flex items-center gap-2 text-blue-600"><HistoryIcon /> History: {viewingHistory.serialNumber}</h3>
              <button onClick={() => setViewingHistory(null)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X className="h-5 w-5"/></button>
            </div>
            <div className="space-y-4">
              {(viewingHistory.history || []).slice().reverse().map((h, i) => (
                <div key={i} className="p-3 border rounded-lg bg-slate-50">
                  <div className="text-[10px] font-bold text-slate-400 uppercase mb-1">{h.field} - {new Date(h.timestamp).toLocaleString()}</div>
                  <div className="text-sm font-semibold">
                    {h.oldValue !== null && <span className="line-through text-slate-300 mr-2">{h.oldValue}</span>}
                    {h.newValue}
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}

      {/* Control Bar */}
      <div className="bg-white p-4 rounded-xl border flex flex-col lg:flex-row gap-4 items-center justify-between shadow-sm">
        <div className="flex flex-col md:flex-row gap-4 w-full lg:w-auto">
          <div className="relative flex-1 md:w-80">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <input 
              type="text" 
              placeholder="Search inventory..." 
              className="w-full pl-10 pr-4 py-2 border rounded-lg text-sm focus:ring-2 focus:ring-blue-500 outline-none" 
              value={searchTerm} 
              onChange={e => setSearchTerm(e.target.value)} 
