import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AssetList } from './components/AssetList';
import { AssetForm } from './components/AssetForm';
import { Dashboard } from './components/Dashboard';
import { UserManual } from './components/UserManual';
import { Login } from './components/Login';
import { Asset } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAsset } from './services/storageService';
import { DatabaseZap, PlusCircle, RotateCw } from 'lucide-react';

type ViewType = 'dashboard' | 'list' | 'add' | 'manual';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('portal_auth') === 'true');
  const [view, setView] = useState<ViewType>('dashboard');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => { if (isAuthenticated) loadData(); }, [isAuthenticated]);

  const loadData = async (isManual = false) => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
      if (isManual) {
        showNotification('Inventory updated successfully', 'success');
      }
    } catch (error: any) {
      setIsConnected(false);
      if (isAuthenticated || isManual) {
        showNotification(error.message || 'DynamoDB Connection failed. Check AWS credentials.', 'error');
      }
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleLogin = async (user: string, _pass: string): Promise<boolean> => {
    if (user.trim() === 'amplify_asset') {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  const handleUpdateAsset = async (serialNumber: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(serialNumber, updates);
      setAssets(prev => prev.map(a => {
        if (a.serialNumber === serialNumber) {
          return { ...a, ...updates };
        }
        return a;
      }));
      showNotification('Asset updated', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    }
  };

  const handleDeleteAssets = async (serials: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => serials.includes(a.serialNumber));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !serials.includes(a.serialNumber)));
      showNotification('Assets removed', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (isLoading && assets.length === 0) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4">
        <RotateCw className="h-8 w-8 text-blue-600 animate-spin" />
        <p className="font-bold text-slate-400">Loading Cloud Inventory...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header currentView={view} onNavigate={setView} onLogout={() => { setIsAuthenticated(false); sessionStorage.removeItem('portal_auth'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        <div className="mb-4 flex justify-end">
          <div className={`px-3 py-1 rounded-full text-[10px] font-bold border flex items-center gap-2 ${isConnected ? 'bg-blue-50 text-blue-700' : 'bg-red-50 text-red-700'}`}>
            <DatabaseZap className="h-3 w-3" /> {isConnected ? 'DynamoDB Linked' : 'Disconnected'}
          </div>
        </div>

        {notification && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-xl shadow-2xl z-50 border bg-white flex items-center gap-3 animate-fade-in ${notification.type === 'success' ? 'text-emerald-700 border-emerald-100 shadow-emerald-500/10' : 'text-red-700 border-red-100 shadow-red-500/10'}`}>
            <div className={`h-2 w-2 rounded-full ${notification.type === 'success' ? 'bg-emerald-500' : 'bg-red-500'}`} />
            <span className="font-semibold">{notification.message}</span>
          </div>
        )}

        {isSaving && (
          <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[200] flex flex-col items-center justify-center gap-4">
            <RotateCw className="h-10 w-10 text-blue-600 animate-spin" />
            <p className="font-extrabold text-slate-800">Syncing with AWS...</p>
          </div>
        )}

        {view === 'dashboard' && <Dashboard assets={assets} />}
        {view === 'manual' && <UserManual />}

        {view === 'list' && (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Inventory</h2>
              <div className="flex gap-2">
                 <button 
                  onClick={() => loadData(true)} 
                  disabled={isLoading}
                  className="px-4 py-2 border rounded-lg text-sm font-bold text-slate-600 bg-white hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm disabled:opacity-50"
                 >
                   <RotateCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
                   {isLoading ? 'Updating...' : 'Refresh'}
                 </button>
                 <button 
                  onClick={() => setView('add')} 
                  className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-600/20"
                 >
                   <PlusCircle className="h-4 w-4" /> Add Asset
                 </button>
              </div>
            </div>
            <AssetList assets={assets} onDelete={handleDeleteAssets} onUpdateAsset={handleUpdateAsset} />
          </div>
        )}

        {view === 'add' && <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />}
      </main>
    </div>
  );
}

export default App;

import React, { useMemo } from 'react';
import { Asset, AssetStatus } from '../types';
import { 
  BarChart3, 
  Package, 
  Globe2, 
  MapPin, 
  Activity, 
  TrendingUp,
  Box,
  Layers
} from 'lucide-react';

interface DashboardProps {
  assets: Asset[];
}

export const Dashboard: React.FC<DashboardProps> = ({ assets }) => {
  const stats = useMemo(() => {
    const total = assets.length;
    const statusCounts: Record<string, number> = {};
    const siteCounts: Record<string, number> = {};
    const countryCounts: Record<string, number> = {};
    const modelStatusCounts: Record<string, Record<string, number>> = {};

    Object.values(AssetStatus).forEach(s => statusCounts[s] = 0);

    assets.forEach(a => {
      // General status, site, country counts
      statusCounts[a.status] = (statusCounts[a.status] || 0) + 1;
      siteCounts[a.siteID] = (siteCounts[a.siteID] || 0) + 1;
      countryCounts[a.country] = (countryCounts[a.country] || 0) + 1;

      // Model based status counts
      if (!modelStatusCounts[a.model]) {
        modelStatusCounts[a.model] = {};
        Object.values(AssetStatus).forEach(s => modelStatusCounts[a.model][s] = 0);
      }
      modelStatusCounts[a.model][a.status]++;
    });

    // Sort breakdowns
    const sortedSites = Object.entries(siteCounts).sort((a, b) => b[1] - a[1]);
    const sortedCountries = Object.entries(countryCounts).sort((a, b) => b[1] - a[1]);
    const sortedModels = Object.entries(modelStatusCounts).sort((a, b) => {
      const totalA = Object.values(a[1]).reduce((sum, val) => sum + val, 0);
      const totalB = Object.values(b[1]).reduce((sum, val) => sum + val, 0);
      return totalB - totalA;
    });

    return { total, statusCounts, sortedSites, sortedCountries, sortedModels };
  }, [assets]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case AssetStatus.Normal: return 'bg-emerald-500';
      case AssetStatus.RMARequested: return 'bg-amber-500';
      case AssetStatus.RMAShipped: return 'bg-blue-500';
      case AssetStatus.RMAEligible: return 'bg-indigo-500';
      case AssetStatus.RMANotEligible: return 'bg-rose-500';
      case AssetStatus.Deprecated: return 'bg-slate-500';
      default: return 'bg-slate-400';
    }
  };

  const getStatusTextColor = (status: string) => {
    switch (status) {
      case AssetStatus.Normal: return 'text-emerald-600';
      case AssetStatus.RMARequested: return 'text-amber-600';
      case AssetStatus.RMAShipped: return 'text-blue-600';
      case AssetStatus.RMAEligible: return 'text-indigo-600';
      case AssetStatus.RMANotEligible: return 'text-rose-600';
      case AssetStatus.Deprecated: return 'text-slate-600';
      default: return 'text-slate-500';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Asset Overview</h2>
        <div className="px-3 py-1 bg-blue-50 text-blue-700 text-xs font-bold rounded-full border border-blue-100 flex items-center gap-2">
          <Activity className="h-3 w-3" /> Live Data
        </div>
      </div>

      {/* Main Stats Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-blue-100 p-3 rounded-xl text-blue-600">
              <Package className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Total Assets</p>
              <p className="text-3xl font-black text-slate-900">{stats.total}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-emerald-100 p-3 rounded-xl text-emerald-600">
              <TrendingUp className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Active/Normal</p>
              <p className="text-3xl font-black text-slate-900">{stats.statusCounts[AssetStatus.Normal]}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-amber-100 p-3 rounded-xl text-amber-600">
              <BarChart3 className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Total RMAs</p>
              <p className="text-3xl font-black text-slate-900">
                {stats.statusCounts[AssetStatus.RMARequested] + stats.statusCounts[AssetStatus.RMAShipped]}
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-indigo-100 p-3 rounded-xl text-indigo-600">
              <Globe2 className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Countries</p>
              <p className="text-3xl font-black text-slate-900">{stats.sortedCountries.length}</p>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
        {/* Status Distribution Visual Bars */}
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
            <Box className="h-5 w-5 text-blue-600" /> Status Distribution
          </h3>
          <div className="space-y-5">
            {Object.entries(stats.statusCounts).map(([status, count]) => {
              const percentage = stats.total > 0 ? (count / stats.total) * 100 : 0;
              if (count === 0 && status === AssetStatus.Unknown) return null;
              return (
                <div key={status} className="space-y-2">
                  <div className="flex justify-between text-sm">
                    <span className="font-bold text-slate-600">{status}</span>
                    <span className="font-mono font-bold text-slate-900">{count}</span>
                  </div>
                  <div className="h-2 w-full bg-slate-100 rounded-full overflow-hidden">
                    <div 
                      className={`h-full transition-all duration-1000 ease-out ${getStatusColor(status)}`}
                      style={{ width: `${percentage}%` }}
                    />
                  </div>
                </div>
              );
            })}
          </div>
        </div>

        {/* Geographic Breakdown Site List */}
        <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
          <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
            <MapPin className="h-5 w-5 text-blue-600" /> Site Breakdown
          </h3>
          <div className="grid grid-cols-1 gap-4 overflow-y-auto max-h-[400px] pr-2">
            {stats.sortedSites.map(([site, count]) => (
              <div key={site} className="flex items-center justify-between p-4 bg-slate-50 rounded-2xl border border-slate-100">
                <div className="flex items-center gap-3">
                  <div className="h-8 w-8 bg-white rounded-lg flex items-center justify-center text-xs font-black text-blue-600 border shadow-sm">
                    {site.substring(0, 3).toUpperCase()}
                  </div>
                  <span className="font-bold text-slate-700">{site}</span>
                </div>
                <div className="flex items-center gap-2">
                  <span className="text-xs font-bold text-slate-400 uppercase">Assets</span>
                  <span className="bg-white px-3 py-1 rounded-lg border text-sm font-black text-slate-900">{count}</span>
                </div>
              </div>
            ))}
            {stats.sortedSites.length === 0 && (
              <p className="text-center py-10 text-slate-400 font-medium">No site data available</p>
            )}
          </div>
        </div>
      </div>

      {/* Model-Based Status Breakdown Table */}
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
        <div className="flex items-center justify-between mb-8">
          <h3 className="text-lg font-bold text-slate-900 flex items-center gap-2">
            <Layers className="h-5 w-5 text-blue-600" /> Status by Model
          </h3>
          <span className="text-xs text-slate-400 font-bold uppercase tracking-widest">Quantity of each status</span>
        </div>

        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="text-[10px] font-bold uppercase text-slate-400 tracking-wider border-b">
                <th className="pb-4 pr-4">Asset Model</th>
                <th className="pb-4 px-2 text-center">Total</th>
                {Object.values(AssetStatus).filter(s => s !== AssetStatus.Unknown).map(s => (
                  <th key={s} className="pb-4 px-2 text-center">{s}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {stats.sortedModels.map(([model, statusObj]) => {
                const totalModel = Object.values(statusObj).reduce((a, b) => a + b, 0);
                return (
                  <tr key={model} className="hover:bg-slate-50/50 transition-colors">
                    <td className="py-4 pr-4 font-bold text-slate-700">{model}</td>
                    <td className="py-4 px-2 text-center">
                      <span className="inline-block bg-slate-100 text-slate-600 px-2 py-0.5 rounded text-xs font-black">
                        {totalModel}
                      </span>
                    </td>
                    {Object.values(AssetStatus).filter(s => s !== AssetStatus.Unknown).map(s => (
                      <td key={s} className="py-4 px-2 text-center">
                        {statusObj[s] > 0 ? (
                          <span className={`text-xs font-black ${getStatusTextColor(s)}`}>
                            {statusObj[s]}
                          </span>
                        ) : (
                          <span className="text-slate-200 text-xs">-</span>
                        )}
                      </td>
                    ))}
                  </tr>
                );
              })}
              {stats.sortedModels.length === 0 && (
                <tr>
                  <td colSpan={10} className="py-10 text-center text-slate-400 font-medium">No model data available</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Country List Footprint */}
      <div className="bg-white p-8 rounded-3xl border border-slate-200 shadow-sm">
        <h3 className="text-lg font-bold text-slate-900 mb-6 flex items-center gap-2">
          <Globe2 className="h-5 w-5 text-blue-600" /> Country Footprint
        </h3>
        <div className="flex flex-wrap gap-4">
          {stats.sortedCountries.map(([country, count]) => (
            <div key={country} className="flex items-center gap-3 px-4 py-3 bg-white border border-slate-100 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
              <span className="font-bold text-slate-800">{country}</span>
              <span className="h-6 w-px bg-slate-100"></span>
              <span className="text-blue-600 font-black">{count}</span>
            </div>
          ))}
          {stats.sortedCountries.length === 0 && (
            <p className="text-slate-400 font-medium">No country data available</p>
          )}
        </div>
      </div>
    </div>
  );
};

import { useState, useEffect } from 'react';
import { Header } from './components/Header';
import { AssetList } from './components/AssetList';
import { AssetForm } from './components/AssetForm';
import { Dashboard } from './components/Dashboard';
import { UserManual } from './components/UserManual';
import { Login } from './components/Login';
import { Asset } from './types';
import { fetchAssets, addAssets, deleteAssets, updateAsset } from './services/storageService';
import { DatabaseZap, PlusCircle, RotateCw } from 'lucide-react';

type ViewType = 'dashboard' | 'list' | 'add' | 'manual';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('portal_auth') === 'true');
  const [view, setView] = useState<ViewType>('dashboard');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => { if (isAuthenticated) loadData(); }, [isAuthenticated]);

  const loadData = async (isManual = false) => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
      if (isManual) {
        showNotification('Inventory updated successfully', 'success');
      }
    } catch (error: any) {
      setIsConnected(false);
      if (isAuthenticated || isManual) {
        showNotification(error.message || 'DynamoDB Connection failed. Check AWS credentials.', 'error');
      }
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleLogin = async (user: string, pass: string): Promise<boolean> => {
    // Strict credential check for security
    if (user.trim() === 'amplify_asset' && pass === 'Portal@2025') {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  const handleUpdateAsset = async (serialNumber: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(serialNumber, updates);
      setAssets(prev => prev.map(a => {
        if (a.serialNumber === serialNumber) {
          return { ...a, ...updates };
        }
        return a;
      }));
      showNotification('Asset updated', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    }
  };

  const handleDeleteAssets = async (serials: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => serials.includes(a.serialNumber));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !serials.includes(a.serialNumber)));
      showNotification('Assets removed', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (isLoading && assets.length === 0) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4">
        <RotateCw className="h-8 w-8 text-blue-600 animate-spin" />
        <p className="font-bold text-slate-400">Loading Cloud Inventory...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header currentView={view} onNavigate={setView} onLogout={() => { setIsAuthenticated(false); sessionStorage.removeItem('portal_auth'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        <div className="mb-4 flex justify-end">
          <div className={`px-3 py-1 rounded-full text-[10px] font-bold border flex items-center gap-2 ${isConnected ? 'bg-blue-50 text-blue-700' : 'bg-red-50 text-red-700'}`}>
            <DatabaseZap className="h-3 w-3" /> {isConnected ? 'DynamoDB Linked' : 'Disconnected'}
          </div>
        </div>

        {notification && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-xl shadow-2xl z-50 border bg-white flex items-center gap-3 animate-fade-in ${notification.type === 'success' ? 'text-emerald-700 border-emerald-100 shadow-emerald-500/10' : 'text-red-700 border-red-100 shadow-red-500/10'}`}>
            <div className={`h-2 w-2 rounded-full ${notification.type === 'success' ? 'bg-emerald-500' : 'bg-red-500'}`} />
            <span className="font-semibold">{notification.message}</span>
          </div>
        )}

        {isSaving && (
          <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[200] flex flex-col items-center justify-center gap-4">
            <RotateCw className="h-10 w-10 text-blue-600 animate-spin" />
            <p className="font-extrabold text-slate-800">Syncing with AWS...</p>
          </div>
        )}

        {view === 'dashboard' && <Dashboard assets={assets} />}
        {view === 'manual' && <UserManual />}

        {view === 'list' && (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Inventory</h2>
              <div className="flex gap-2">
                 <button 
                  onClick={() => loadData(true)} 
                  disabled={isLoading}
                  className="px-4 py-2 border rounded-lg text-sm font-bold text-slate-600 bg-white hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm disabled:opacity-50"
                 >
                   <RotateCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
                   {isLoading ? 'Updating...' : 'Refresh'}
                 </button>
                 <button 
                  onClick={() => setView('add')} 
                  className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-600/20"
                 >
                   <PlusCircle className="h-4 w-4" /> Add Asset
                 </button>
              </div>
            </div>
            <AssetList assets={assets} onDelete={handleDeleteAssets} onUpdateAsset={handleUpdateAsset} />
          </div>
        )}

        {view === 'add' && <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />}
      </main>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { ShieldCheck, User, Key, AlertCircle, Loader2, Database } from 'lucide-react';

interface LoginProps {
  onLogin: (user: string, pass: string) => Promise<boolean>;
}

export const Login: React.FC<LoginProps> = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState(false);
  const [isLoggingIn, setIsLoggingIn] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(false);
    setIsLoggingIn(true);

    // Artificial delay for security feel
    await new Promise(r => setTimeout(r, 800));

    const success = await onLogin(username, password);
    if (!success) {
      setError(true);
      setIsLoggingIn(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4 relative overflow-hidden">
      {/* Background Decorations */}
      <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-blue-600/20 rounded-full blur-[120px]"></div>
      <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-indigo-600/20 rounded-full blur-[120px]"></div>

      <div className="w-full max-w-md z-10">
        <div className="bg-white/10 backdrop-blur-xl border border-white/10 rounded-3xl shadow-2xl overflow-hidden p-8 md:p-10">
          <div className="flex flex-col items-center mb-10">
            <div className="bg-blue-600 p-4 rounded-2xl shadow-lg shadow-blue-500/30 mb-4">
              <Database className="h-10 w-10 text-white" />
            </div>
            <h1 className="text-2xl font-bold text-white tracking-tight text-center">AssetTrack IT Portal</h1>
            <p className="text-slate-400 text-sm mt-2 text-center">Inventory & RMA Management System</p>
          </div>

          {error && (
            <div className="mb-6 p-4 bg-red-500/10 border border-red-500/20 rounded-xl flex items-center gap-3 text-red-400 text-sm animate-fade-in">
              <AlertCircle className="h-5 w-5 flex-shrink-0" />
              <span>Invalid credentials. Please verify username and password.</span>
            </div>
          )}

          <form onSubmit={handleSubmit} className="space-y-6">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Username *</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-500" />
                <input
                  type="text"
                  required
                  autoFocus
                  className="w-full bg-slate-800/50 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-600"
                  placeholder="amplify_asset"
                  value={username}
                  onChange={e => setUsername(e.target.value)}
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-widest mb-2 ml-1">Password *</label>
              <div className="relative">
                <Key className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-slate-500" />
                <input
                  type="password"
                  required
                  className="w-full bg-slate-800/50 border border-white/10 rounded-xl py-3 pl-12 pr-4 text-white focus:ring-2 focus:ring-blue-500 outline-none transition-all placeholder:text-slate-600"
                  placeholder="••••••••"
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={isLoggingIn}
              className="w-full bg-blue-600 hover:bg-blue-500 text-white font-bold py-4 rounded-xl shadow-lg shadow-blue-600/20 transition-all flex items-center justify-center gap-2 group disabled:opacity-70"
            >
              {isLoggingIn ? (
                <Loader2 className="h-5 w-5 animate-spin" />
              ) : (
                <>
                  <ShieldCheck className="h-5 w-5 group-hover:scale-110 transition-transform" />
                  Secure Sign In
                </>
              )}
            </button>
          </form>

          <div className="mt-8 text-center flex flex-col gap-2">
            <p className="text-[10px] text-slate-500 uppercase font-bold tracking-widest">
              Authorized Personnel Only
            </p>
            <p className="text-[10px] text-blue-500/60 font-medium">
              Credentials Required: amplify_asset / Portal@2025
            </p>
          </div>
        </div>
      </div>
    </div>
  );
};

// Add React import for types and namespace access
import React, { useState, useRef } from 'react';
import { Asset, AssetStatus } from '../types';
import { parseAssetsFromText } from '../services/geminiService';
// Added Sparkles to the imported icons from lucide-react
import { Save, AlertCircle, Upload, Info, Sparkles } from 'lucide-react';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetFormProps {
  onAddAssets: (assets: Asset[]) => void;
  onCancel: () => void;
}

export const AssetForm: React.FC<AssetFormProps> = ({ onAddAssets, onCancel }) => {
  const [mode, setMode] = useState<'manual' | 'ai' | 'bulk'>('manual');
  const [manualForm, setManualForm] = useState({
    model: '',
    serialNumber: '',
    siteID: '',
    country: '',
    comments: '',
    status: AssetStatus.Normal
  });

  const [aiInput, setAiInput] = useState('');
  const [isProcessing, setIsProcessing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [bulkPreview, setBulkPreview] = useState<Asset[]>([]);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Validation Logic
  const isValidSiteID = (id: string) => /^[a-zA-Z][a-zA-Z0-9]*$/.test(id);

  const handleManualSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);

    if (!manualForm.model || !manualForm.serialNumber || !manualForm.siteID) {
      setError("Please fill in required fields (Model, Serial, SiteID).");
      return;
    }

    if (!isValidSiteID(manualForm.siteID)) {
      setError("Invalid SiteID. It must start with a letter and contain only letters and numbers.");
      return;
    }

    onAddAssets([{ ...manualForm, createdAt: Date.now() }]);
  };

  const handleAiParse = async () => {
    if (!aiInput.trim()) return;
    setIsProcessing(true);
    setError(null);
    try {
      const parsedData = await parseAssetsFromText(aiInput);
      if (parsedData.length === 0) {
        setError("No assets found in text.");
      } else {
        const validAssets: Asset[] = [];
        const invalidSites: string[] = [];

        parsedData.forEach(p => {
          const siteID = ((p as any).siteID || (p as any).siteId || 'Unknown').trim();
          if (isValidSiteID(siteID)) {
            validAssets.push({
              serialNumber: p.serialNumber || 'UNKNOWN-' + Date.now(),
              model: p.model || 'Unknown',
              siteID: siteID,
              country: p.country || '',
              comments: (p as any).comments || '',
              status: (p.status as AssetStatus) || AssetStatus.Normal,
              createdAt: Date.now()
            });
          } else {
            invalidSites.push(siteID);
          }
        });

        if (validAssets.length === 0 && invalidSites.length > 0) {
          setError(`Found ${invalidSites.length} assets but all had invalid SiteID formats (must start with letter).`);
        } else {
          if (invalidSites.length > 0) {
            console.warn(`Skipped ${invalidSites.length} assets due to invalid SiteID format:`, invalidSites);
          }
          onAddAssets(validAssets);
        }
      }
    } catch (err) {
      setError("AI Processing failed.");
    } finally {
      setIsProcessing(false);
    }
  };

  const processRowToAsset = (row: any): Asset | null => {
    const normalized: Record<string, any> = {};
    Object.keys(row).forEach(k => normalized[k.toLowerCase().trim().replace(/[^a-z0-9]/g, '')] = row[k]);

    const model = normalized['model'] || normalized['assetmodel'] || normalized['product'];
    const serial = normalized['serialnumber'] || normalized['serial'] || normalized['sn'];
    const site = normalized['siteid'] || normalized['site'];
    const country = normalized['country'] || normalized['region'];
    const comments = normalized['comments'] || normalized['rmastatus'] || normalized['notes'];

    if (model && serial && site) {
      const siteIDStr = String(site).trim();
      if (isValidSiteID(siteIDStr)) {
        return {
          serialNumber: String(serial).trim(),
          model: String(model).trim(),
          siteID: siteIDStr,
          country: country ? String(country).trim() : '',
          comments: comments ? String(comments).trim() : '',
          status: AssetStatus.Normal,
          createdAt: Date.now()
        };
      }
    }
    return null;
  };

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (evt) => {
      try {
        const data = file.name.endsWith('.csv') 
          ? Papa.parse(evt.target?.result as string, { header: true }).data
          : XLSX.utils.sheet_to_json(XLSX.read(evt.target?.result, { type: 'binary' }).Sheets[XLSX.read(evt.target?.result, { type: 'binary' }).SheetNames[0]]);

        const assets = data.map(processRowToAsset).filter((a): a is Asset => a !== null);
        if (assets.length === 0) setError("No valid assets found. SiteID must start with a letter and headers must include Model, Serial Number, and SiteID.");
        else setBulkPreview(assets);
      } catch (err) { setError("File parsing failed."); }
    };
    file.name.endsWith('.csv') ? reader.readAsText(file) : reader.readAsBinaryString(file);
  };

  return (
    <div className="max-w-3xl mx-auto">
      <div className="mb-8 flex gap-2 p-1 bg-slate-100 rounded-lg justify-center">
        {['manual', 'bulk', 'ai'].map((m) => (
          <button key={m} onClick={() => setMode(m as any)} className={`px-4 py-2 rounded-md text-sm font-medium capitalize ${mode === m ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-600'}`}>
            {m} entry
          </button>
        ))}
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 p-8">
        {error && <div className="mb-6 p-4 bg-red-50 text-red-700 rounded-lg flex items-center gap-2 text-sm border border-red-100 animate-fade-in"><AlertCircle className="h-5 w-5 flex-shrink-0" />{error}</div>}

        {mode === 'manual' && (
          <form onSubmit={handleManualSubmit} className="space-y-6">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Asset Model *</label>
                <input type="text" required className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="e.g. Dell Latitude 5420" value={manualForm.model} onChange={e => setManualForm({...manualForm, model: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Serial Number *</label>
                <input type="text" required className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all font-mono" placeholder="e.g. ABC123XYZ" value={manualForm.serialNumber} onChange={e => setManualForm({...manualForm, serialNumber: e.target.value})} />
              </div>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">SiteID *</label>
                <input 
                  type="text" 
                  required 
                  className={`w-full px-4 py-2 border rounded-lg outline-none transition-all ${manualForm.siteID && !isValidSiteID(manualForm.siteID) ? 'border-red-500 bg-red-50 focus:ring-red-500' : 'focus:ring-blue-500'}`} 
                  placeholder="e.g. LDN01" 
                  value={manualForm.siteID} 
                  onChange={e => setManualForm({...manualForm, siteID: e.target.value})} 
                />
                {manualForm.siteID && !isValidSiteID(manualForm.siteID) && (
                  <p className="text-[10px] text-red-600 font-bold mt-1 ml-1 flex items-center gap-1">
                    <Info className="h-3 w-3" /> Must start with a letter (A-Z)
                  </p>
                )}
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Country</label>
                <input type="text" className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="e.g. UK" value={manualForm.country} onChange={e => setManualForm({...manualForm, country: e.target.value})} />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Initial Status</label>
                <select className="w-full px-4 py-2 border rounded-lg focus:ring-2 focus:ring-blue-500 outline-none transition-all" value={manualForm.status} onChange={e => setManualForm({...manualForm, status: e.target.value as AssetStatus})}>
                  {Object.values(AssetStatus).map(s => <option key={s} value={s}>{s}</option>)}
                </select>
              </div>
            </div>
            <div className="space-y-1">
               <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Comments</label>
               <textarea className="w-full px-4 py-2 border rounded-lg h-24 focus:ring-2 focus:ring-blue-500 outline-none transition-all" placeholder="Additional notes or RMA details..." value={manualForm.comments} onChange={e => setManualForm({...manualForm, comments: e.target.value})} />
            </div>
            <div className="flex gap-4">
              <button 
                type="submit" 
                disabled={!isValidSiteID(manualForm.siteID)}
                className="flex-1 bg-blue-600 text-white py-3 rounded-lg font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Save className="h-5 w-5" />Save Asset
              </button>
              <button type="button" onClick={onCancel} className="px-6 py-3 border rounded-lg hover:bg-slate-50 transition-colors font-bold text-slate-600">Cancel</button>
            </div>
          </form>
        )}

        {mode === 'bulk' && (
          <div className="space-y-6 text-center">
            {bulkPreview.length === 0 ? (
              <>
                <div className="border-2 border-dashed border-slate-300 rounded-xl p-12 hover:bg-slate-50 transition-colors cursor-pointer group" onClick={() => fileInputRef.current?.click()}>
                  <input type="file" accept=".csv,.xlsx,.xls" className="hidden" ref={fileInputRef} onChange={handleFileUpload} />
                  <Upload className="h-12 w-12 text-blue-600 mx-auto mb-4 group-hover:scale-110 transition-transform" />
                  <h3 className="text-lg font-bold text-slate-800">Upload Excel or CSV</h3>
                  <p className="text-slate-500 text-sm mt-2">Required: Model, Serial Number, SiteID</p>
                  <p className="text-[10px] text-blue-400 font-bold uppercase tracking-widest mt-4">SiteID must start with a letter</p>
                </div>
                <button onClick={onCancel} className="text-slate-500 font-bold hover:text-slate-800 transition-colors">Back</button>
              </>
            ) : (
              <div className="space-y-4 animate-fade-in">
                <div className="flex justify-between items-center px-1">
                  <h3 className="font-bold text-slate-800">Preview: {bulkPreview.length} Valid Assets</h3>
                  <button onClick={() => setBulkPreview([])} className="text-xs text-red-600 font-bold hover:underline">Clear</button>
                </div>
                <div className="max-h-60 overflow-y-auto border rounded-lg shadow-inner">
                  <table className="w-full text-xs text-left">
                    <thead className="bg-slate-50 sticky top-0">
                      <tr>
                        <th className="p-3 border-b">Model</th>
                        <th className="p-3 border-b">Serial</th>
                        <th className="p-3 border-b">SiteID</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y">
                      {bulkPreview.map((a, i) => (
                        <tr key={i} className="hover:bg-slate-50">
                          <td className="p-3">{a.model}</td>
                          <td className="p-3 font-mono text-[10px]">{a.serialNumber}</td>
                          <td className="p-3 font-semibold text-blue-600">{a.siteID}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                </div>
                <div className="flex gap-4">
                  <button onClick={() => onAddAssets(bulkPreview)} className="flex-1 bg-emerald-600 text-white py-3 rounded-lg font-bold hover:bg-emerald-700 transition-colors shadow-lg shadow-emerald-600/20">
                    Import {bulkPreview.length} Assets
                  </button>
                  <button onClick={() => setBulkPreview([])} className="px-6 py-3 border rounded-lg hover:bg-slate-50 transition-colors font-bold text-slate-600">Cancel</button>
                </div>
              </div>
            )}
          </div>
        )}

        {mode === 'ai' && (
          <div className="space-y-6">
            <div className="flex justify-between items-center px-1">
               <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Unstructured Text Input</label>
               <span className="text-[10px] text-indigo-500 font-bold flex items-center gap-1"><Sparkles className="h-3 w-3" /> AI Engine Active</span>
            </div>
            <textarea 
              className="w-full px-4 py-3 border rounded-lg h-48 font-mono text-sm focus:ring-2 focus:ring-indigo-500 outline-none transition-all shadow-inner" 
              value={aiInput} 
              onChange={e => setAiInput(e.target.value)} 
              placeholder="Paste email, logs, or chat messages here...&#10;e.g. 'Laptop S/N ABC123 LDN-01 is shipped to London'" 
            />
            <div className="flex gap-4">
              <button 
                onClick={handleAiParse} 
                disabled={isProcessing || !aiInput.trim()} 
                className="flex-1 bg-indigo-600 text-white py-3 rounded-lg font-bold disabled:opacity-50 hover:bg-indigo-700 transition-colors shadow-lg shadow-indigo-600/20 flex items-center justify-center gap-2"
              >
                {isProcessing ? <Loader2 className="h-5 w-5 animate-spin" /> : <Sparkles className="h-5 w-5" />}
                {isProcessing ? "Analyzing..." : "AI Extract & Save"}
              </button>
              <button onClick={onCancel} className="px-6 py-3 border rounded-lg hover:bg-slate-50 transition-colors font-bold text-slate-600">Cancel</button>
            </div>
            <p className="text-[10px] text-slate-400 text-center italic">Only assets with SiteIDs starting with a letter will be saved.</p>
          </div>
        )}
      </div>
    </div>
  );
};

const Loader2 = ({ className }: { className?: string }) => (
  <svg className={className} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 1 1-6.219-8.56"/></svg>
);

import React, { useMemo } from 'react';
import { Asset, AssetStatus } from '../types';
import { 
  BarChart3, 
  Package, 
  Globe2, 
  MapPin, 
  Activity, 
  TrendingUp,
  Box,
  Layers
} from 'lucide-react';

interface DashboardProps {
  assets: Asset[];
}

export const Dashboard: React.FC<DashboardProps> = ({ assets }) => {
  const stats = useMemo(() => {
    const total = assets.length;
    const statusCounts: Record<string, number> = {};
    const siteCounts: Record<string, number> = {};
    const countryCounts: Record<string, number> = {};
    const modelStatusCounts: Record<string, Record<string, number>> = {};

    Object.values(AssetStatus).forEach(s => statusCounts[s] = 0);

    assets.forEach(a => {
      // General status, site, country counts
      statusCounts[a.status] = (statusCounts[a.status] || 0) + 1;
      siteCounts[a.siteID] = (siteCounts[a.siteID] || 0) + 1;
      countryCounts[a.country] = (countryCounts[a.country] || 0) + 1;

      // Model based status counts
      if (!modelStatusCounts[a.model]) {
        modelStatusCounts[a.model] = {};
        Object.values(AssetStatus).forEach(s => modelStatusCounts[a.model][s] = 0);
      }
      modelStatusCounts[a.model][a.status]++;
    });

    // Sort breakdowns
    const sortedSites = Object.entries(siteCounts).sort((a, b) => b[1] - a[1]);
    const sortedCountries = Object.entries(countryCounts).sort((a, b) => b[1] - a[1]);
    const sortedModels = Object.entries(modelStatusCounts).sort((a, b) => {
      // Fix: Explicitly type reduce accumulators and current values to avoid unknown arithmetic errors
      const totalA = Object.values(a[1]).reduce((sum: number, val: number) => sum + val, 0);
      const totalB = Object.values(b[1]).reduce((sum: number, val: number) => sum + val, 0);
      return totalB - totalA;
    });

    return { total, statusCounts, sortedSites, sortedCountries, sortedModels };
  }, [assets]);

  const getStatusColor = (status: string) => {
    switch (status) {
      case AssetStatus.Normal: return 'bg-emerald-500';
      case AssetStatus.RMARequested: return 'bg-amber-500';
      case AssetStatus.RMAShipped: return 'bg-blue-500';
      case AssetStatus.RMAEligible: return 'bg-indigo-500';
      case AssetStatus.RMANotEligible: return 'bg-rose-500';
      case AssetStatus.Deprecated: return 'bg-slate-500';
      default: return 'bg-slate-400';
    }
  };

  const getStatusTextColor = (status: string) => {
    switch (status) {
      case AssetStatus.Normal: return 'text-emerald-600';
      case AssetStatus.RMARequested: return 'text-amber-600';
      case AssetStatus.RMAShipped: return 'text-blue-600';
      case AssetStatus.RMAEligible: return 'text-indigo-600';
      case AssetStatus.RMANotEligible: return 'text-rose-600';
      case AssetStatus.Deprecated: return 'text-slate-600';
      default: return 'text-slate-500';
    }
  };

  return (
    <div className="space-y-8 animate-fade-in">
      <div className="flex items-center justify-between">
        <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Asset Overview</h2>
        <div className="px-3 py-1 bg-blue-50 text-blue-700 text-xs font-bold rounded-full border border-blue-100 flex items-center gap-2">
          <Activity className="h-3 w-3" /> Live Data
        </div>
      </div>

      {/* Main Stats Summary Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-blue-100 p-3 rounded-xl text-blue-600">
              <Package className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Total Assets</p>
              <p className="text-3xl font-black text-slate-900">{stats.total}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-emerald-100 p-3 rounded-xl text-emerald-600">
              <TrendingUp className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Active/Normal</p>
              <p className="text-3xl font-black text-slate-900">{stats.statusCounts[AssetStatus.Normal]}</p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-amber-100 p-3 rounded-xl text-amber-600">
              <BarChart3 className="h-6 w-6" />
            </div>
            <div>
              <p className="text-xs font-bold text-slate-400 uppercase tracking-widest">Total RMAs</p>
              <p className="text-3xl font-black text-slate-900">
                {stats.statusCounts[AssetStatus.RMARequested] + stats.statusCounts[AssetStatus.RMAShipped]}
              </p>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
          <div className="flex items-center gap-4">
            <div className="bg-indigo-100 p-3 rounded-xl text-indigo-600">
              <Globe2 className="h-6 w-6" />
            </div>
