                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-1">
                        {isEditing ? (
                          <>
                            <button onClick={handleSaveEdit} disabled={siteIDInvalid} className={`p-2 rounded-lg transition-all ${siteIDInvalid ? 'text-slate-200 cursor-not-allowed' : 'text-emerald-600 hover:bg-emerald-50'}`}>
                              <Check className="h-4 w-4" />
                            </button>
                            <button onClick={cancelEditing} className="p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-lg transition-all">
