import { useState, useEffect } from 'react';
import { Header } from './components/Header.tsx';
import { AssetList } from './components/AssetList.tsx';
import { AssetForm } from './components/AssetForm.tsx';
import { Dashboard } from './components/Dashboard.tsx';
import { UserManual } from './components/UserManual.tsx';
import { Login } from './components/Login.tsx';
import { Asset } from './types.ts';
import { fetchAssets, addAssets, deleteAssets, updateAsset, bulkUpdateAssets } from './services/storageService.ts';
import { DatabaseZap, RotateCw, PlusCircle } from 'lucide-react';

type ViewType = 'dashboard' | 'list' | 'add' | 'manual';

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => sessionStorage.getItem('portal_auth') === 'true');
  const [view, setView] = useState<ViewType>('dashboard');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [notification, setNotification] = useState<{message: string, type: 'success' | 'error'} | null>(null);
  const [isLoading, setIsLoading] = useState(true);
  const [isSaving, setIsSaving] = useState(false);
  const [isConnected, setIsConnected] = useState<boolean | null>(null);

  useEffect(() => { if (isAuthenticated) loadData(); }, [isAuthenticated]);

  const loadData = async (isManual = false) => {
    setIsLoading(true);
    try {
      const data = await fetchAssets();
      setAssets(data);
      setIsConnected(true);
      if (isManual) {
        showNotification('Inventory updated successfully', 'success');
      }
    } catch (error: any) {
      setIsConnected(false);
      if (isAuthenticated || isManual) {
        showNotification(error.message || 'DynamoDB Connection failed. Check AWS credentials.', 'error');
      }
    } finally { 
      setIsLoading(false); 
    }
  };

  const handleLogin = async (user: string, pass: string): Promise<boolean> => {
    const env = (import.meta as any).env || {};
    const validUsername = env.VITE_PORTAL_USERNAME || process.env.VITE_PORTAL_USERNAME || 'amplify_asset';
    const validPassword = env.VITE_PORTAL_PASSWORD || process.env.VITE_PORTAL_PASSWORD;

    if (user.trim() === validUsername && pass === validPassword) {
      setIsAuthenticated(true);
      sessionStorage.setItem('portal_auth', 'true');
      return true;
    }
    return false;
  };

  const showNotification = (message: string, type: 'success' | 'error') => {
    setNotification({ message, type });
    setTimeout(() => setNotification(null), 5000);
  };

  const handleAddAssets = async (newAssets: Asset[]) => {
    setIsSaving(true);
    try {
      await addAssets(newAssets);
      setAssets(prev => [...prev, ...newAssets]);
      setView('list');
      showNotification(`Saved ${newAssets.length} asset(s) to DynamoDB`, 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  const handleUpdateAsset = async (serialNumber: string, updates: Partial<Asset>) => {
    try {
      await updateAsset(serialNumber, updates);
      setAssets(prev => prev.map(a => {
        if (a.serialNumber === serialNumber) {
          return { ...a, ...updates };
        }
        return a;
      }));
      showNotification('Asset updated', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    }
  };

  const handleBulkTransfer = async (serials: string[], newSiteID: string) => {
    setIsSaving(true);
    try {
      await bulkUpdateAssets(serials, { siteID: newSiteID });
      setAssets(prev => prev.map(a => {
        if (serials.includes(a.serialNumber)) {
          // Note: Local state won't show the full history until refresh, but will show new SiteID
          return { ...a, siteID: newSiteID };
        }
        return a;
      }));
      showNotification(`Transferred ${serials.length} assets to ${newSiteID}`, 'success');
      // Refresh to get full history from server
      loadData();
    } catch (error: any) {
      showNotification(error.message, 'error');
    } finally {
      setIsSaving(false);
    }
  };

  const handleDeleteAssets = async (serials: string[]) => {
    setIsSaving(true);
    try {
      const assetsToDelete = assets.filter(a => serials.includes(a.serialNumber));
      await deleteAssets(assetsToDelete);
      setAssets(prev => prev.filter(a => !serials.includes(a.serialNumber)));
      showNotification('Assets removed', 'success');
    } catch (error: any) { 
      showNotification(error.message, 'error'); 
    } finally { 
      setIsSaving(false); 
    }
  };

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  if (isLoading && assets.length === 0) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50 gap-4">
        <RotateCw className="h-8 w-8 text-blue-600 animate-spin" />
        <p className="font-bold text-slate-400">Loading Cloud Inventory...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex flex-col bg-slate-50">
      <Header currentView={view} onNavigate={setView} onLogout={() => { setIsAuthenticated(false); sessionStorage.removeItem('portal_auth'); }} />
      <main className="flex-1 max-w-7xl mx-auto px-4 py-8 w-full">
        <div className="mb-4 flex justify-end">
          <div className={`px-3 py-1 rounded-full text-[10px] font-bold border flex items-center gap-2 ${isConnected ? 'bg-blue-50 text-blue-700' : 'bg-red-50 text-red-700'}`}>
            <DatabaseZap className="h-3 w-3" /> {isConnected ? 'DynamoDB Linked' : 'Disconnected'}
          </div>
        </div>

        {notification && (
          <div className={`fixed bottom-8 left-1/2 -translate-x-1/2 px-6 py-4 rounded-xl shadow-2xl z-[250] border bg-white flex items-center gap-3 animate-fade-in ${notification.type === 'success' ? 'text-emerald-700 border-emerald-100 shadow-emerald-500/10' : 'text-red-700 border-red-100 shadow-red-500/10'}`}>
            <div className={`h-2 w-2 rounded-full ${notification.type === 'success' ? 'bg-emerald-500' : 'bg-red-500'}`} />
            <span className="font-semibold">{notification.message}</span>
          </div>
        )}

        {isSaving && (
          <div className="fixed inset-0 bg-white/60 backdrop-blur-sm z-[300] flex flex-col items-center justify-center gap-4">
            <RotateCw className="h-10 w-10 text-blue-600 animate-spin" />
            <p className="font-extrabold text-slate-800">Syncing with AWS...</p>
          </div>
        )}

        {view === 'dashboard' && <Dashboard assets={assets} />}
        {view === 'manual' && <UserManual />}

        {view === 'list' && (
          <div className="space-y-6">
            <div className="flex justify-between items-end">
              <h2 className="text-3xl font-extrabold text-slate-900 tracking-tight">Inventory</h2>
              <div className="flex gap-2">
                 <button 
                  onClick={() => loadData(true)} 
                  disabled={isLoading}
                  className="px-4 py-2 border rounded-lg text-sm font-bold text-slate-600 bg-white hover:bg-slate-50 transition-all flex items-center gap-2 shadow-sm disabled:opacity-50"
                 >
                   <RotateCw className={`h-4 w-4 ${isLoading ? 'animate-spin' : ''}`} />
                   {isLoading ? 'Updating...' : 'Refresh'}
                 </button>
                 <button 
                  onClick={() => setView('add')} 
                  className="bg-blue-600 text-white px-6 py-2 rounded-lg font-bold flex items-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-600/20"
                 >
                   <PlusCircle className="h-4 w-4" /> Add Asset
                 </button>
              </div>
            </div>
            <AssetList 
              assets={assets} 
              onDelete={handleDeleteAssets} 
              onUpdateAsset={handleUpdateAsset} 
              onBulkTransfer={handleBulkTransfer}
            />
          </div>
        )}

        {view === 'add' && <AssetForm onAddAssets={handleAddAssets} onCancel={() => setView('list')} />}
      </main>
    </div>
  );
}

export default App;

import React, { useState, useMemo, useEffect } from 'react';
import { Asset, AssetStatus } from '../types';
import { 
  Search, 
  Trash2, 
  Loader2, 
  Globe, 
  AlertTriangle, 
  X, 
  History as HistoryIcon,
  ChevronLeft,
  ChevronRight,
  Rows,
  FileDown,
  FileText,
  Table as TableIcon,
  Pencil,
  Check,
  XCircle,
  Info,
  ArrowRightLeft
} from 'lucide-react';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

interface AssetListProps {
  assets: Asset[];
  onDelete: (ids: string[]) => void;
  onUpdateAsset: (serialNumber: string, updates: Partial<Asset>) => Promise<void>;
  onBulkTransfer: (ids: string[], newSiteID: string) => Promise<void>;
}

export const AssetList: React.FC<AssetListProps> = ({ assets, onDelete, onUpdateAsset, onBulkTransfer }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState<string>('All');
  const [selectedSerials, setSelectedSerials] = useState<Set<string>>(new Set());
  const [updatingId, setUpdatingId] = useState<string | null>(null);
  const [showExportMenu, setShowExportMenu] = useState(false);

  // Modal states
  const [transferModalOpen, setTransferModalOpen] = useState(false);
  const [newSiteID, setNewSiteID] = useState('');
  const [isProcessingBulk, setIsProcessingBulk] = useState(false);

  // Inline Edit State
  const [editingSerial, setEditingSerial] = useState<string | null>(null);
  const [editData, setEditData] = useState<Partial<Asset>>({});

  // Pagination State
  const [itemsPerPage, setItemsPerPage] = useState<number>(50);
  const [currentPage, setCurrentPage] = useState<number>(1);

  const [assetsToDelete, setAssetsToDelete] = useState<Asset[] | null>(null);
  const [viewingHistory, setViewingHistory] = useState<Asset | null>(null);

  // Validation Helper
  const isValidSiteID = (id: string | undefined) => {
    if (!id) return false;
    return /^[a-zA-Z][a-zA-Z0-9]*$/.test(id);
  };

  // Helper for status colors
  const getStatusClasses = (status: AssetStatus) => {
    switch (status) {
      case AssetStatus.Normal: 
        return 'bg-emerald-50 text-emerald-700 border-emerald-200';
      case AssetStatus.RMARequested: 
        return 'bg-amber-50 text-amber-700 border-amber-200';
      case AssetStatus.RMAShipped: 
        return 'bg-blue-50 text-blue-700 border-blue-200';
      case AssetStatus.RMAEligible: 
        return 'bg-indigo-50 text-indigo-700 border-indigo-200';
      case AssetStatus.RMANotEligible: 
        return 'bg-rose-50 text-rose-700 border-rose-200';
      case AssetStatus.Deprecated: 
        return 'bg-slate-100 text-slate-600 border-slate-200';
      default: 
        return 'bg-slate-50 text-slate-500 border-slate-200';
    }
  };

  // Reset page on search or filter change
  useEffect(() => {
    setCurrentPage(1);
  }, [searchTerm, statusFilter, itemsPerPage]);

  const filtered = useMemo(() => assets.filter(a => {
    const term = searchTerm.toLowerCase();
    const matchesSearch = 
      a.model.toLowerCase().includes(term) || 
      a.serialNumber.toLowerCase().includes(term) || 
      a.siteID.toLowerCase().includes(term) || 
      a.country.toLowerCase().includes(term) || 
      (a.comments || '').toLowerCase().includes(term);
    return matchesSearch && (statusFilter === 'All' || a.status === statusFilter);
  }), [assets, searchTerm, statusFilter]);

  const totalPages = Math.ceil(filtered.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const currentItems = filtered.slice(startIndex, startIndex + itemsPerPage);
  const allOnPageSelected = currentItems.length > 0 && currentItems.every(a => selectedSerials.has(a.serialNumber));

  const toggleSelect = (s: string) => {
    const next = new Set(selectedSerials);
    next.has(s) ? next.delete(s) : next.add(s);
    setSelectedSerials(next);
  };

  const handlePageChange = (newPage: number) => {
    if (newPage >= 1 && newPage <= totalPages) {
      setCurrentPage(newPage);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  const startEditing = (asset: Asset) => {
    setEditingSerial(asset.serialNumber);
    setEditData({
      model: asset.model,
      serialNumber: asset.serialNumber,
      siteID: asset.siteID,
      country: asset.country
    });
  };

  const cancelEditing = () => {
    setEditingSerial(null);
    setEditData({});
  };

  const handleSaveEdit = async () => {
    if (!editingSerial) return;
    if (!isValidSiteID(editData.siteID)) return;

    setUpdatingId(editingSerial);
    try {
      await onUpdateAsset(editingSerial, editData);
      setEditingSerial(null);
      setEditData({});
    } finally {
      setUpdatingId(null);
    }
  };

  const handleBulkTransferSubmit = async () => {
    if (!isValidSiteID(newSiteID)) return;
    setIsProcessingBulk(true);
    try {
      await onBulkTransfer(Array.from(selectedSerials), newSiteID);
      setSelectedSerials(new Set());
      setTransferModalOpen(false);
      setNewSiteID('');
    } finally {
      setIsProcessingBulk(false);
    }
  };

  const handleBulkDeleteSubmit = () => {
    const targets = assets.filter(a => selectedSerials.has(a.serialNumber));
    setAssetsToDelete(targets);
  };

  const prepareExportData = () => {
    return filtered.map(a => ({
      'Model': a.model,
      'Serial Number': a.serialNumber,
      'Site ID': a.siteID,
      'Country': a.country,
      'Status': a.status,
      'Comments': a.comments || '',
      'Created At': new Date(a.createdAt).toLocaleString(),
      'History Events': (a.history || []).length
    }));
  };

  const exportCSV = () => {
    const data = prepareExportData();
    const csv = Papa.unparse(data);
    const blob = new Blob([csv], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    const url = URL.createObjectURL(blob);
    link.setAttribute('href', url);
    link.setAttribute('download', `AssetTrack_Export_${new Date().toISOString().split('T')[0]}.csv`);
    link.style.visibility = 'hidden';
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    setShowExportMenu(false);
  };

  const exportExcel = () => {
    const data = prepareExportData();
    const worksheet = XLSX.utils.json_to_sheet(data);
    const workbook = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(workbook, worksheet, "Assets");
    XLSX.writeFile(workbook, `AssetTrack_Export_${new Date().toISOString().split('T')[0]}.xlsx`);
    setShowExportMenu(false);
  };

  return (
    <div className="space-y-6 relative">
      {/* Transfer Modal */}
      {transferModalOpen && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[150] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl p-8 max-w-lg w-full shadow-2xl animate-fade-in">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-slate-900 flex items-center gap-2">
                <ArrowRightLeft className="h-5 w-5 text-blue-600" /> Bulk Site Transfer
              </h3>
              <button onClick={() => setTransferModalOpen(false)} className="p-2 hover:bg-slate-100 rounded-full transition-colors"><X className="h-5 w-5"/></button>
            </div>

            <div className="space-y-6">
              <div className="p-4 bg-blue-50 border border-blue-100 rounded-2xl">
                <p className="text-sm text-blue-700 font-medium leading-relaxed">
                  You are transferring <span className="font-black underline">{selectedSerials.size}</span> selected assets 
                  to a new destination. This will be recorded in the audit history of each asset.
                </p>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-bold text-slate-400 uppercase tracking-widest ml-1">Destination SiteID *</label>
                <input 
                  type="text" 
                  autoFocus
